-- 1. Paaspop
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('paaspop','Paaspop','Paaspop is een van de oudste festivals van Nederland en groeide sinds de eerste editie in 1979 uit van een lokaal buurtfeest bij een manege tot een driedaags festival met honderden acts in Schijndel. Wat begon met zaagsel op de grond, twee lichtmasten en twee bandjes voor zo veel bezoekers, trekt inmiddels tienduizenden festivalgangers die met Pasen naar De Molenheide komen. Ondanks de schaalvergroting heeft Paaspop zijn Brabantse, gemoedelijke sfeer weten te behouden: voor veel vriendengroepen uit de regio is een bezoek jaarlijks vaste prik, en buurtbewoners zijn nog altijd betrokken bij de organisatie. Het festival wordt vaak in een adem genoemd met Pinkpop, dat zijn naam ontleent aan Paaspop en in hetzelfde jaar werd opgericht. Muzikaal is Paaspop breed georienteerd: van gevestigde pop- en rocknamen tot een verrassend uitgebreid programma met meer dan 350 acts verspreid over meerdere podia, aangevuld met kermisachtige attracties, kraampjes en acrobatiek. Die combinatie van muziek en spektakel geeft het festival een familiair, ongedwongen karakter dat afwijkt van de grotere, gepolijste festivals. De editie van 2026 vond plaats van vrijdag 3 tot en met zondag 5 april en bood een line-up met onder meer Sean Paul, Scooter, Tom Odell, DI-RECT, Kensington en Racoon, aangevuld met talent uit eigen land. Voor bezoekers uit de regio Meierijstad is Paaspop niet alleen een festival, maar ook een lentetraditie die de aftrap van het buitenseizoen markeert.','{pop,rock,mixed}','Sean Paul, Scooter, Tom Odell, DI-RECT, Kensington, Racoon, Antoon, Pommelien Thijs, De Jeugd van Tegenwoordig, S10','Schijndel','De Molenheide','Noord-Brabant','2026-04-03','2026-04-05','https://www.paaspop.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 89.00, 'EUR', 'https://www.paaspop.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'paaspop';

-- 2. Bospop
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('bospop','Bospop','Bospop is een van de meest gerespecteerde rock- en popfestivals van Nederland en staat al decennialang bekend om zijn kwalitatieve, op klassieke rock georienteerde line-up en de bosrijke locatie Weerterbergen bij Weert. In tegenstelling tot festivals die vooral inzetten op de nieuwste hypes, kiest Bospop bewust voor een mix van gevestigde internationale rocklegendes en verrassende namen uit de rock- en bluesscene, wat het festival een tijdloos karakter geeft. Bezoekers roemen vooral de intieme sfeer ondanks de duizenden aanwezigen: het bosrijke terrein zorgt voor schaduw en beschutting, en het driedaagse programma is doorgaans compact genoeg om vrijwel alle genomineerde acts te kunnen zien. Voor 2026 heeft de organisatie een indrukwekkende line-up samengesteld met Lenny Kravitz, Volbeat en Moby als headliners, aangevuld met namen als Counting Crows, ZZ Top, Kaiser Chiefs, Chris Isaak, Within Temptation en Anouk. In totaal telt de affiche 46 acts, verdeeld over de drie festivaldagen van vrijdag 10 tot en met zondag 12 juli. Bospop trekt een trouw publiek dat het festival soms al vanaf de jaren tachtig bezoekt, wat resulteert in een ontspannen, weinig commerciele sfeer vergeleken met grotere mainstage-festivals. De prijzen zijn dit jaar wel gestegen ten opzichte van voorgaande edities, maar dat heeft de populariteit van het festival niet aangetast: kaarten voor het weekend zijn traditiegetrouw snel uitverkocht bij liefhebbers van kwaliteitsrock.','{rock,pop}','Lenny Kravitz, Volbeat, Moby, Counting Crows, ZZ Top, Kaiser Chiefs, Chris Isaak, Within Temptation, Anouk, Kensington','Weert','Weerterbergen','Limburg','2026-07-10','2026-07-12','https://www.bospop.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 117.50, 'EUR', 'https://www.bospop.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'bospop';

-- 3. Zwarte Cross
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('zwarte-cross','Zwarte Cross','Zwarte Cross is uitgegroeid tot het grootste festival van Nederland en onderscheidt zich door de unieke combinatie van muziek, motorcross, comedy, theater en kermisattracties op een voormalig vliegveld bij Lichtenvoorde. Wat ooit begon als een lokaal motorcrossevenement, is nu een vierdaags spektakel dat jaarlijks honderdduizenden bezoekers trekt en zich moeilijk in een genre laat vangen. Het publiek is uitgesproken breed en enthousiast: overdag hoofdbangen bij rockbands, in de avond dansen op grote podia, en tussendoor genieten van waanzinnige stuntshows en de kenmerkende crossraces die het festival zijn naam gaven. Die combinatie van adrenaline en muziek is uniek in het Nederlandse festivallandschap en trekt zowel rockliefhebbers als feestvierders aan die simpelweg op zoek zijn naar een onvergetelijk weekend. Muzikaal biedt Zwarte Cross voor 2026 een enorme breedte: van rock en pop tot hardstyle en Nederlandstalige feestmuziek, verspreid over tientallen podia en met in totaal bijna 420 muziek-, theater- en performanceacts. Bevestigde namen zijn onder meer Jannes, Kaiser Chiefs, Ofenbach, Razorlight, Dropkick Murphys en BOKKERS. Het festival vindt plaats van donderdag 16 tot en met zondag 19 juli, met de zaterdag inmiddels uitverkocht terwijl de overige dagen nog tickets beschikbaar hebben. De informele, ongepolijste sfeer, het brede theaterprogramma en de herkenbare mix van boerenland-nostalgie en hedendaagse festivalcultuur maken Zwarte Cross tot een fenomeen dat moeilijk te vergelijken is met andere Nederlandse festivals.','{rock,pop,mixed,hardstyle}','Jannes, Kaiser Chiefs, Ofenbach, Razorlight, Dropkick Murphys, BOKKERS, Victor Mids, Cosmic Psychos, Bente','Lichtenvoorde','Vliegveld Lichtenvoorde','Gelderland','2026-07-16','2026-07-19','https://www.zwartecross.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 65.00, 'EUR', 'https://www.zwartecross.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'zwarte-cross';

-- 4. Best Kept Secret
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('best-kept-secret','Best Kept Secret','Best Kept Secret geldt als een van de smaakvolste boutique-festivals van Nederland en onderscheidt zich door een zorgvuldig samengestelde line-up met veel aandacht voor indie, alternatieve rock en artistiek interessante namen naast grotere headliners. Het festival, gehouden op de bosrijke camping van Beekse Bergen in Hilvarenbeek, staat bekend om zijn ontspannen, weinig massale sfeer: ondanks de aanwezigheid van internationale topacts blijft het overzichtelijk genoeg om je niet verloren te voelen tussen de menigte. Bezoekers prijzen vooral de kwaliteit van de line-up boven de kwantiteit, en de organisatie kiest bewust voor een mix van gevestigde namen en artiesten die net op het punt staan door te breken. De editie van 2026, gehouden van vrijdag 12 tot en met zondag 14 juni, had Gorillaz, Jack White en Nick Cave and The Bad Seeds als headliners, met een verder programma vol namen als Ethel Cain, Wolf Alice, Mac DeMarco, De La Soul en Sudan Archives. Die combinatie van alternatieve rock, hiphop en singer-songwriters onderstreept het brede maar consequent smaakvolle muzikale profiel van het festival. Best Kept Secret trekt een publiek dat vooral gedreven wordt door muzikale nieuwsgierigheid, en de bosrijke, groene setting van Beekse Bergen zorgt voor een rustgevende tegenhanger van de energie op de podia. Voor liefhebbers van doordachte programmering is dit festival al jaren een vast onderdeel van de zomeragenda.','{indie,rock,pop}','Gorillaz, Jack White, Nick Cave and The Bad Seeds, Ethel Cain, Wolf Alice, Mac DeMarco, De La Soul, Sudan Archives','Hilvarenbeek','Beekse Bergen','Noord-Brabant','2026-06-12','2026-06-14','https://bestkeptsecret.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 294.00, 'EUR', 'https://bestkeptsecret.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'best-kept-secret';

-- 5. Concert at SEA
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('concert-at-sea','Concert at SEA','Concert at SEA is een van de bekendste kustfestivals van Nederland en dankt zijn populariteit aan de unieke locatie op de Brouwersdam, tussen Schouwen-Duiveland en Goeree-Overflakkee. De setting aan zee, met het strand en de duinen als decor, geeft het festival een herkenbare zomerse sfeer die het onderscheidt van festivals op traditionele weilandlocaties. Het publiek bestaat vooral uit mensen die houden van een brede mix van Nederlandstalige en internationale pop, gecombineerd met een strandvakantiegevoel: overdag zon en zee, in de avond livemuziek onder de sterrenhemel. Muzikaal richt het festival zich op toegankelijke, meezingbare pop en rock, met een programmering die zowel gevestigde internationale artiesten als de grote Nederlandse namen combineert. De editie van 2026 vond plaats van donderdag 25 tot en met zaterdag 27 juni en bood onder meer Counting Crows, James Arthur en Kensington, aangevuld met Nederlandse artiesten als Miss Montreal, Krezip, DI-RECT en Suzan & Freek. Concert at SEA behoort door deze combinatie van herkenbare hits en een unieke ligging tot de snelst uitverkochte festivals van het land: tickets voor 2026 waren dan ook al ruim voor de festivaldagen niet meer verkrijgbaar. De sfeer wordt vaak omschreven als toegankelijk en gezellig, met een publiek dat uiteenloopt van jonge stelletjes tot gezinnen die samen genieten van de combinatie van strand, zee en muziek.','{pop,mixed}','Counting Crows, James Arthur, Kensington, Miss Montreal, Krezip, DI-RECT, Suzan & Freek','Renesse','Brouwersdam / Kabbelaarsbank','Zeeland','2026-06-25','2026-06-27','https://www.concertatsea.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 85.00, 'EUR', 'https://www.concertatsea.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'concert-at-sea';

-- 6. Zomerparkfeest
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('zomerparkfeest','Zomerparkfeest','Zomerparkfeest is een van de grootste gratis toegankelijke festivals van Nederland en onderscheidt zich door de combinatie van muziek met dans, theater, kunst en wetenschap in het groene Julianapark in Venlo. Waar veel festivals zich puur op muziek richten, is Zomerparkfeest een breed cultuurfestival waarbij de programmering bewust een mix biedt van gevestigde artiesten en nieuwe, opkomende makers uit verschillende disciplines. Het gratis karakter van het festival zorgt voor een laagdrempelige, gemengde bezoekersgroep: van gezinnen met kinderen overdag tot een jonger publiek dat in de avond naar de podia trekt. Met ruim 90.000 bezoekers over vier dagen en circa honderd acts behoort het tot de grotere festivals in zijn categorie, ondanks de afwezigheid van een toegangsprijs. De editie van 2026 loopt van donderdag 13 tot en met zondag 16 augustus, met wisselende openingstijden per dag: de donderdag start om 18.00 uur, de overige dagen doorgaans vanaf 13.00 uur. Het parkkarakter van de locatie, met veel groen en ruimte, geeft het festival een relaxte, weinig commerciele sfeer die aansluit bij het culturele, laagdrempelige profiel. Zomerparkfeest is daarmee minder een traditioneel muziekfestival en meer een meerdaags cultureel volksfeest, waar de combinatie van kunst, theater en muziek zorgt voor een divers en verrassend programma dat elk jaar weer publiek van alle leeftijden weet te trekken.','{mixed,pop}','Venlo','Julianapark','Limburg','2026-08-13','2026-08-16','https://www.zomerparkfeest.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
