-- 7. Dauwpop
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('dauwpop','Dauwpop','Dauwpop is een van de langstlopende festivals van Overijssel en vierde in 2026 zijn dertigste editie in het Hellendoornse Bos. Wat in 1995 begon als eendaags festival op Hemelvaartsdag, groeide uit tot een tweedaags evenement met eigen camping, waarbij bezoekers het festival vooral roemen om de gemoedelijke sfeer en de sterke, verrassende line-up. Het karakter van Dauwpop wordt vaak omschreven als een ontdekfestival: bezoekers lopen langs een podium, horen een act die ze nog niet kennen, en blijven hangen omdat de muziek ze weet te raken. Die combinatie van nieuwsgierigheid en gemoedelijkheid heeft het festival de afgelopen jaren tot een veelgeprezen naam gemaakt, met erkenningen als beste festival van Nederland in 2023 en de derde plek in 2024. De camping, toepasselijk Waud genaamd, zorgt voor een trouwe groep terugkerende bezoekers die het festivalweekend als vast onderdeel van hun jaarkalender beschouwen. De editie van 2026 vond plaats op vrijdag 29 en zaterdag 30 mei in het bos bij Hellendoorn, waarbij het festivalterrein voor twee dagen veranderde in een kleurrijke wereld vol muziek, natuur en onverwachte ontmoetingen. Ondanks de gestegen kosten in de festivalwereld probeert de organisatie de instapprijs bewust behapbaar te houden, wat aansluit bij het toegankelijke, weinig opzichtige karakter van het festival. Voor liefhebbers van een overzichtelijk, sfeervol festival zonder overdaad aan grote namen is Dauwpop een vaste waarde in de regio.','{pop,mixed}','Hellendoorn','Sportpark ''t Midholt','Overijssel','2026-05-29','2026-05-30','https://www.dauwpop.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
