from festivals where slug = 'dauwpop';

-- 8. Huntenpop
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('huntenpop','Huntenpop','Huntenpop vierde in 2026 zijn 35e editie en is daarmee een van de meest gevestigde regionale festivals van de Achterhoek. Het festival vindt plaats op het industriele DRU-terrein in Ulft, een voormalig fabriekscomplex dat een industriele, authentieke uitstraling geeft aan het tweedaagse evenement. In tegenstelling tot festivals die vooral op jongeren mikken, trekt Huntenpop een breed, generatie-overstijgend publiek dat houdt van een mix van Nederlandstalige pop, rock en tributebands. De programmering combineert grote namen met feestacts als tributebands voor Supertramp en Iron Maiden, wat het festival een herkenbare, weinig pretentieuze sfeer geeft. Voor 2026, van vrijdag 21 tot en met zaterdag 22 augustus, bevestigde de organisatie een line-up met onder meer DI-RECT, Suzan & Freek, BLOF, Son Mieux, Bente en BOKKERS, aangevuld met Nederlandse rockveteranen als DeWolff en Bintangs. De combinatie van gevestigde Nederpop-namen met wat kleinschaliger tribute- en feestacts maakt het festival aantrekkelijk voor een breed publiek dat houdt van meezingen en gezelligheid boven een puur artistiek programma. Het DRU-terrein, met zijn industriele architectuur en compacte opzet, zorgt voor een intieme sfeer ondanks de bekende namen op de affiche. Huntenpop is daarmee typerend voor het soort regionale zomerfestival dat generaties bezoekers aan zich weet te binden, zonder de allure te verliezen van een festival dat al 35 jaar meegaat.','{pop,mixed}','DI-RECT, Suzan & Freek, BLOF, Son Mieux, Bente, BOKKERS, DeWolff, Bintangs, Pommelien Thijs, Therapy?','Ulft','DRU Park','Gelderland','2026-08-21','2026-08-22','https://www.huntenpop.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 22.50, 'EUR', 'https://www.huntenpop.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'huntenpop';

-- 9. Oerol
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('oerol','Oerol','Oerol is een van de grootste locatietheaterfestivals van Europa en onderscheidt zich fundamenteel van muziekfestivals doordat niet een podium, maar het hele eiland Terschelling het decor vormt. Tien dagen lang worden duinen, bossen en stranden omgetoverd tot speelplekken voor site-specific theater, straattheater, beeldende kunst en muziek, waarbij het landschap niet alleen decor is maar ook actief onderdeel van de voorstellingen. Jaarlijks trekt het festival zo n 55.000 bezoekers die vooral komen voor de artistieke verrassing: theatervoorstellingen op ongewone buiten- en binnenlocaties, kunstinstallaties verspreid over het eiland en optredens op festivalhart de Deining en het intieme Bostheater. De sfeer op Oerol wordt vaak omschreven als los en nieuwsgierig: het publiek bestaat uit kunstliefhebbers die niet houden van vaste kaders, met veel jonge makers, wandelschoenen en gesprekken bij het kampvuur. Anders dan bij muziekfestivals draait het minder om headliners en meer om ontdekking en verwondering. De editie van 2026 liep van vrijdag 12 tot en met zondag 21 juni en bood tien dagen lang een gevarieerd programma van gesproken woord, straattheater en muziek. Een festivalbandje geeft bezoekers tien dagen lang onbeperkte toegang tot het eiland vol kunst, met aparte, voordeligere tarieven voor jongeren en kinderen. Voor wie op zoek is naar een festivalervaring die verder gaat dan muziek alleen, geldt Oerol al decennialang als een uniek en onvervangbaar evenement in de Nederlandse festivalkalender.','{folk,mixed}','Terschelling','Hele eiland Terschelling','Friesland','2026-06-12','2026-06-21','https://www.oerol.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 75.00, 'EUR', 'https://www.oerol.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'oerol';

-- 10. Welcome to the Village
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('welcome-to-the-village','Welcome to the Village','Welcome to the Village is een meerdaags, interdisciplinair festival in Leeuwarden dat sinds de oprichting door de gelijknamige stichting in 2014 muziek combineert met kunst, theater, food en design. Het festival positioneert zich bewust als experimenteel popfestival: de programmering beweegt van rockgitaren tot hiphop en singer-songwriters, en biedt daarnaast ruimte aan opkomend talent naast gevestigde namen. Bezoekers prijzen vooral de compleetheid van de ervaring, waarbij eten, line-up, locatie, sfeer en publiek als een geheel worden ervaren in plaats van als losse onderdelen. De ligging in een recreatiegebied bij Leeuwarden zorgt voor een groene, ontspannen setting die goed aansluit bij het alternatieve, kunstzinnige karakter van het festival. In tegenstelling tot festivals die vooral leunen op bekende hitnamen, kiest Welcome to the Village bewust voor artistieke verdieping: naast muziek is er veel aandacht voor beeldende kunst, talks en vormgeving, wat het festival aantrekkelijk maakt voor een publiek dat op zoek is naar meer dan alleen concerten. De editie van 2026 vond plaats van donderdag 4 tot en met zondag 7 juni en bouwde voort op de reputatie van het festival als broedplaats voor nieuwe muziek en cultuur in het noorden van Nederland. Door de combinatie van Friese couleur locale, een internationaal georienteerde programmering en een uitgesproken duurzame en creatieve uitstraling, onderscheidt Welcome to the Village zich duidelijk van grotere, meer commerciele festivals in de rest van het land.','{mixed,pop,indie}','Leeuwarden','De Griffioen','Friesland','2026-06-04','2026-06-07','https://www.welcometothevillage.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 50.00, 'EUR', 'https://www.welcometothevillage.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'welcome-to-the-village';

-- 11. Parkpop
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('parkpop','Parkpop','Parkpop is een van de grootste gratis muziekfestivals van Europa en een begrip in Den Haag sinds de eerste editie in de jaren tachtig. Het festival vond decennialang plaats in het Zuiderpark, maar verhuisde naar het centraal gelegen Malieveld omdat deze locatie beter bereikbaar is voor het grote publiek. De gratis toegang maakt Parkpop toegankelijk voor een breed en divers publiek: gezinnen, jongeren en oudere bezoekers mengen zich moeiteloos tussen elkaar op het overzichtelijke Malieveld. Muzikaal richt het festival zich van oudsher op brede, meezingbare pop met een mix van internationale acts en de grote Nederlandse namen, wat aansluit bij het volksfeestkarakter van het evenement. De 40e editie, gehouden op zondag 12 juni 2026, bood meer dan dertig acts verspreid over de dag, met onder meer UB40 featuring Ali Campbell, DI-RECT, Maan, Goldband en Froukje op de affiche. Froukje opende het festival in de vroege middag, waarna het programma via onder meer Kevin & The Animals en Donnie XL opbouwde naar het slotoptreden van UB40 in de avond. Het jubileum onderstreepte de status van Parkpop als een van de oudste en meest laagdrempelige festivaltradities van Nederland. Waar veel festivals de afgelopen jaren duurder en exclusiever zijn geworden, blijft Parkpop trouw aan zijn oorspronkelijke uitgangspunt: gratis, toegankelijke popmuziek voor iedereen in een ontspannen parksetting midden in de stad.','{pop,mixed}','UB40 ft. Ali Campbell, DI-RECT, Maan, Kevin & The Animals, Goldband, Froukje, Donnie XL','Den Haag','Malieveld','Zuid-Holland','2026-06-12','2026-06-12','https://www.parkpop.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
