from festivals where slug = 'parkpop';

-- 12. De Amsterdamse Zomer
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('de-amsterdamse-zomer','De Amsterdamse Zomer','De Amsterdamse Zomer is een relatief jong maar snel gegroeid festival dat Nederlandstalige artiesten combineert met een indrukwekkend decor: het Olympisch Stadion in Amsterdam. De iconische locatie, gebouwd voor de Olympische Spelen van 1928, geeft het festival een unieke uitstraling die afwijkt van festivals op weilanden of parkeerterreinen. Het programma richt zich vooral op de brede Nederlandse levensliedcultuur en meezingpop, met een line-up die generaties aanspreekt: van jongere artiesten tot gevestigde namen uit het Nederlandstalige repertoire. Deze combinatie van nostalgie en herkenbaarheid maakt het festival populair bij een publiek dat houdt van samen zingen en een feestelijke, ongecompliceerde sfeer. Voor de editie van 2026 zijn onder meer Andre Hazes, Jeroen van der Boom, Kris Kross Amsterdam, Mart Hoogkamer, Xander de Buisonje, Jan Smit, Gerard Joling en Tino Martin aangekondigd, een line-up die het brede palet van de Nederlandse feestmuziek weerspiegelt. De setting in het stadion, met tribunes rondom het veld, zorgt voor een concertachtige ervaring die toch de energie van een festival behoudt. De populariteit van het festival is de afgelopen jaren sterk gegroeid, met verkochte dagen als gevolg: de zaterdag van de editie 2026 was al ruim van tevoren uitverkocht. Voor liefhebbers van Nederlandstalige muziek en een feestelijke sfeer in een historische setting is De Amsterdamse Zomer inmiddels een vaste waarde geworden in de Amsterdamse festivalzomer.','{pop,folk,mixed}','Andre Hazes, Jeroen van der Boom, Kris Kross Amsterdam, Mart Hoogkamer, Xander de Buisonje, Jan Smit, Gerard Joling, Tino Martin, Bente','Amsterdam','Olympisch Stadion','Noord-Holland','2026-07-03','2026-07-04','https://www.deamsterdamsezomer.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 49.95, 'EUR', 'https://www.deamsterdamsezomer.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'de-amsterdamse-zomer';

-- 13. Valkhof Festival
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('valkhof-festival','Valkhof Festival','Valkhof Festival is een gratis toegankelijk festival dat samenvalt met de Nijmeegse Vierdaagse en zich onderscheidt door een uitgesproken alternatieve, internationaal georienteerde programmering in het historische Valkhofpark. In plaats van te kiezen voor grote, bekende namen, profileert het festival zich als podium voor minder voor de hand liggende acts uit binnen- en buitenland, met een sterke focus op indie, folk, noise rock, hiphop en clubmuziek. Die keuze geeft Valkhof Festival een underground karakter dat afwijkt van de meeste grote gratis festivals in Nederland, en trekt een publiek aan dat gericht is op muzikale ontdekking in plaats van herkenning. Het park zelf, gelegen op een historische heuvel met uitzicht over de Waal, voegt een bijzondere, sfeervolle laag toe aan het festival: de combinatie van oude muren, groen en de rivier zorgt voor een unieke setting die niet te vergelijken is met een regulier festivalterrein. Voor 2026 kondigde de organisatie een lijst van meer dan dertig artiesten aan, waaronder internationale acts als het Australische Gee Tee en het Japanse Ni-Hao, aangevuld met Nederlandse namen als Dressed Like Boys, Bricknasty, Naaz en De Nachtwacht. Daarnaast biedt het festival met Club Voerweg een uitgebreid nachtprogramma met dance- en clubacts. De timing rond de Vierdaagse zorgt bovendien voor een extra levendige sfeer in de stad, waarbij wandelaars en festivalgangers Nijmegen samen tot een bruisend zomerdecor maken.','{pop,mixed}','Dressed Like Boys, Bricknasty, Naaz, De Nachtwacht, Gee Tee, Ni-Hao','Nijmegen','Valkhofpark','Gelderland','2026-07-17','2026-07-19','https://www.valkhoffestival.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 0.00, 'EUR', 'https://www.valkhoffestival.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'valkhof-festival';

-- 14. Into The Great Wide Open
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('into-the-great-wide-open','Into The Great Wide Open','Into The Great Wide Open is een van de meest geliefde boutique-festivals van Nederland en dankt zijn status vooral aan de unieke locatie: het autoluwe eiland Vlieland, waar natuur en muziek volledig met elkaar verweven zijn. Het festival profileert zich bewust als kleinschalig en artistiek verantwoord alternatief voor de grote, commerciele festivals, met een sterke nadruk op duurzaamheid, aandacht voor het landschap en een zorgvuldig samengestelde line-up vol opkomend talent en interessante, minder voor de hand liggende namen. Bezoekers reizen per boot naar het eiland, wat het festival vanaf het begin een reisgevoel en een gevoel van afzondering geeft dat op het vasteland niet te ervaren is. De sfeer wordt vaak omschreven als ontspannen en gemeenschappelijk: kleine podia verspreid over de bossen en duinen, korte loopafstanden en een publiek dat komt voor muzikale verrassing in plaats van headliner-jacht. Voor de editie van 2026, van donderdag 27 tot en met zondag 30 augustus, kondigde de organisatie namen aan als MARO, Friko, Little Grandad en HATIHATI, een selectie die het internationale en genre-overstijgende karakter van het festival onderstreept. Ondanks de kleinschaligheid is het festival enorm populair: de kaartverkoop startte eind januari en binnen korte tijd waren alle volwassenenkaarten uitverkocht, met alleen nog kinderkaarten beschikbaar en een wachtlijst voor de rest. De combinatie van eilandbeleving, duurzaamheid en muzikale kwaliteit maakt Into The Great Wide Open tot een van de snelst uitverkochte festivals van het land.','{indie,pop,mixed}','MARO, Friko, Little Grandad, HATIHATI, Suzan Peeters','Vlieland','Hele eiland Vlieland','Friesland','2026-08-27','2026-08-30','https://intothegreatwideopen.nl','sold_out',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 285.00, 'EUR', 'https://intothegreatwideopen.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'into-the-great-wide-open';

-- 15. Misty Fields
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('misty-fields','Misty Fields','Misty Fields is een kleinschalig alternatief muziekfestival dat sinds 2006 een vaste plek heeft in de Brabantse regio rond Heusden, dicht bij natuurgebied De Groote Peel. Het festival profileert zich uitgesproken als een festival voor liefhebbers van alternatieve rock, garage, psychedelica en aanverwante genres, met een programmering die bewust weinig mainstream namen bevat en juist ruimte biedt aan buitenlandse cultbands en veelbelovende nieuwkomers. Verspreid over meerdere intieme podia in een bosrijke, groene omgeving aan het water biedt het festival een sfeer die wordt omschreven als avontuurlijk en authentiek: het publiek bestaat vooral uit oprechte muziekliefhebbers die de kleinschaligheid en ontdekkingsfactor van het festival waarderen boven grootschalig entertainment. In tegenstelling tot festivals met een brede, publieksvriendelijke affiche kiest Misty Fields bewust voor scherpte in de programmering, met meer dan veertig bands verdeeld over vier podia gedurende het festivalweekend. Voor de editie van 2026 bevestigde de organisatie onder andere Ty Segall, Squid, Allah-Las en Man/Woman/Chainsaw, namen die de rauwe, gitaargedreven signatuur van het festival goed weerspiegelen. De combinatie van een natuurlijke, wat verscholen locatie met een scherp geprogrammeerde affiche zorgt ervoor dat Misty Fields al jaren een vaste waarde is voor liefhebbers van indierock en garage in Nederland, ook al blijft het qua schaal bewust bescheiden vergeleken met de grotere festivals in de regio.','{indie,rock}','Ty Segall, Squid, Allah-Las, Man/Woman/Chainsaw, Golomb, Weird Nightmare','Heusden','Engelermeer','Noord-Brabant','2026-06-06','2026-06-07','https://www.mistyfields.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 112.00, 'EUR', 'https://www.mistyfields.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'misty-fields';

-- 16. London Calling
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('london-calling','London Calling','London Calling is een gevestigde naam binnen de Nederlandse festivalcultuur en wordt georganiseerd in de intieme setting van poppodium Paradiso in Amsterdam. Het festival onderscheidt zich door de nadrukkelijke focus op nieuwe, opkomende bands binnen indie, rock en punk, vaak internationale acts die nog aan het begin van hun carriere staan. Waar veel grote festivals draaien om bekende headliners, draait London Calling juist om ontdekking: de programmering bestaat doorgaans uit een reeks kortere sets van uiteenlopende bands verspreid over de verschillende zalen van Paradiso, wat het festival een clubmatige, energieke sfeer geeft. De historische locatie zelf, een voormalige kerk met een rijke concertgeschiedenis, versterkt het gevoel dat je een unieke, kleinschalige muziekervaring meemaakt in plaats van een grootschalig festivalbezoek. London Calling wordt door de jaren heen meerdere keren per jaar georganiseerd, telkens met een wisselende affiche van nieuwe namen uit binnen- en buitenland, waarbij eerdere edities acts hebben geprogrammeerd als Panic Shack, The New Eves en Cardinals. Voor de editie later in 2026 in Amsterdam is de volledige line-up nog niet bevestigd; de organisatie kondigt doorgaans in de aanloop naar het evenement een reeks nieuwe, veelbelovende bands aan. Voor liefhebbers van gitaarmuziek en het ontdekken van bands voordat ze doorbreken, geldt London Calling al jarenlang als een betrouwbare en laagdrempelige aanrader binnen de Amsterdamse concertagenda.','{indie,rock,punk}','Amsterdam','Paradiso','Noord-Holland','2026-11-14','2026-11-14','https://www.londoncalling.nl','announced',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', null, 'EUR', 'https://www.londoncalling.nl', 'unknown', '2026-07-03T09:00:00Z'
from festivals where slug = 'london-calling';

-- 17. Bevrijdingsfestival Groningen
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('bevrijdingsfestival-groningen','Bevrijdingsfestival Groningen','Bevrijdingsfestival Groningen is een van de grootste bevrijdingsfestivals van Nederland en trekt jaarlijks op 5 mei zo n 135.000 bezoekers naar het Stadspark in Groningen. Het festival maakt deel uit van het landelijke netwerk van bevrijdingsfestivals dat de vrijheid herdenkt en viert, en onderscheidt zich door de combinatie van een enorm open festivalterrein met meerdere podia voor uiteenlopende genres: van pop en rock tot urban, elektronische muziek en spoken word. De Drafbaan binnen het Stadspark biedt de ruimte om podia, foodpleinen en kunstprojecten breed uit te spreiden, wat het festival een ruimtelijk, weinig opgepropt karakter geeft vergeleken met kleinere stadsfestivals. Het thema vrijheid staat centraal in de programmering, onder meer via de traditionele Ambassadeurs van de Vrijheid-optredens waarin muziek en boodschap samenkomen. Voor de editie van 2026 bevestigde de organisatie een line-up met onder meer Douwe Bob, Sophie Straat, ELMER, SEF en Maan, aangevuld met een optreden van de Jostiband samen met Reinier Zonneveld. Die combinatie van gevestigde Nederpopnamen, urban artiesten en een bijzondere samenwerking tussen klassiek en elektronisch geeft het festival een verrassende, gelaagde programmering. Doordat het festival volledig gratis toegankelijk is, trekt het een zeer divers publiek van alle leeftijden, van gezinnen die overdag komen tot een jonger publiek dat later op de dag blijft hangen bij de dance-podia. Daarmee is Bevrijdingsfestival Groningen niet alleen een muziekfestival, maar ook een belangrijk jaarlijks moment van gezamenlijke viering in de stad.','{pop,mixed}','Douwe Bob, Sophie Straat, ELMER, SEF, Maan, Reinier Zonneveld, Joshua Idehen','Groningen','Stadspark','Groningen','2026-05-05','2026-05-05','https://bevrijdingsfestivalgroningen.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 0.00, 'EUR', 'https://bevrijdingsfestivalgroningen.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'bevrijdingsfestival-groningen';

-- 18. Bevrijdingsfestival Wageningen
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('bevrijdingsfestival-wageningen','Bevrijdingsfestival Wageningen','Bevrijdingsfestival Wageningen heeft een bijzondere historische lading: in Hotel De Wereld in Wageningen werd op 5 mei 1945 de capitulatie van de Duitse troepen in Nederland getekend, waardoor de stad een centrale plek inneemt in de nationale herdenkings- en bevrijdingstraditie. Het festival, ook wel Bevrijdingsfestival Gelderland genoemd, combineert daardoor een uitgesproken maatschappelijke en historische boodschap met een breed muzikaal programma verspreid over vijftien podia in de binnenstad. Muzikaal beweegt de line-up van rock en Nederlandstalige hits tot dance, techno en pop, wat zorgt voor een zeer divers publiek dat door de hele binnenstad verspreid raakt langs de verschillende podia. Het thema voor de editie van 2026, Begrijp de geschiedenis, nodigde bezoekers uitdrukkelijk uit om samen met ooggetuigen en hun kleinkinderen stil te staan bij de littekens van de Tweede Wereldoorlog, wat het festival een reflectieve laag geeft die niet elk bevrijdingsfestival heeft. Op de mainstage traden in 2026 onder meer De Nachtwacht, de Jostiband, Bente, Hiigo en Jungle by Night op, aangevuld met artiesten als Douwe Bob en The Darkraver op andere podia. Met meer dan tachtig acts verspreid over de stad en volledig gratis toegang, behoort het festival tot de grotere bevrijdingsevenementen van het land. De combinatie van historisch besef, gratis toegankelijkheid en een verrassend brede muzikale programmering maakt Bevrijdingsfestival Wageningen tot een uniek jaarlijks moment waarin viering en herdenking hand in hand gaan.','{pop,mixed}','De Nachtwacht, Jostiband, Bente, Hiigo, Jungle by Night, Douwe Bob, The Darkraver','Wageningen','Bevrijdingsterrein / Wageningse Berg','Gelderland','2026-05-05','2026-05-05','https://www.bevrijdingsfestivalgelderland.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 0.00, 'EUR', 'https://www.bevrijdingsfestivalgelderland.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'bevrijdingsfestival-wageningen';

-- 19. Bevrijdingsfestival Brabant (Den Bosch)
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('bevrijdingsfestival-den-bosch','Bevrijdingsfestival Brabant','Bevrijdingsfestival Brabant vindt jaarlijks plaats op 5 mei in ''s-Hertogenbosch en is het aangewezen bevrijdingsfestival voor de provincie Noord-Brabant. Het festival wordt georganiseerd op de Pettelaarse Schans nabij het Bossche Broek, een groene, waterrijke locatie aan de rand van de stad die zorgt voor een open, ontspannen festivalsfeer. Met circa 35.000 bezoekers is het kleinschaliger dan de bevrijdingsfestivals in bijvoorbeeld Groningen of Wageningen, wat het festival een net iets intiemer karakter geeft terwijl de gratis toegang en het maatschappelijke thema onveranderd centraal blijven staan. De programmering combineert doorgaans pop, rock en urban muziek verspreid over drie podia, met ruimte voor zowel gevestigde artiesten als opkomend talent. Voor de editie van 2026 bevestigde de organisatie een affiche van 24 artiesten, waaronder MEROL met een set die electropunk combineert met rock- en techno-invloeden, de Belgische rockband K''s Choice met hun bekende hit Not an Addict, en rapper Josylvio, bekend van hits als Ride Or Die en Catch Up. Die combinatie van uiteenlopende genres binnen een compact programma zorgt voor een gevarieerde dagindeling waarin bezoekers eenvoudig tussen de verschillende podia Horizon, De Kaap en Bries kunnen wisselen. Het bevrijdingsthema wordt, net als bij de andere bevrijdingsfestivals, ingevuld met aandacht voor vrijheid en herdenking, wat het festival naast een feestelijk karakter ook een reflectieve laag meegeeft binnen de Brabantse 5 mei-viering.','{pop,mixed}','MEROL, K''s Choice, Josylvio','''s-Hertogenbosch','Bossche Broek','Noord-Brabant','2026-05-05','2026-05-05','https://www.bevrijdingsfestivalbrabant.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 0.00, 'EUR', 'https://www.bevrijdingsfestivalbrabant.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'bevrijdingsfestival-den-bosch';

-- 20. Bevrijdingsfestival Drenthe
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('bevrijdingsfestival-drenthe','Bevrijdingsfestival Drenthe','Bevrijdingsfestival Drenthe vindt jaarlijks plaats op 5 mei in Assen en combineert, net als de andere bevrijdingsfestivals, gratis toegankelijke muziek met aandacht voor vrijheid en herdenking. Het festival wordt georganiseerd op en rond het Stadsbroek en kent een overzichtelijke opzet met een hoofdpodium en enkele kleinere podia, waaronder een dancepodium en een talentpodium in samenwerking met Kunst & Cultuur Drenthe. Die kleinschaligere schaal ten opzichte van bijvoorbeeld Groningen geeft het festival een net iets persoonlijker karakter, waarbij regionaal talent nadrukkelijk de kans krijgt om zich te presenteren naast grotere namen. Het programma opent traditiegetrouw met het optreden van de Ambassadeur van de Vrijheid, waarna de dag zich muzikaal verder opbouwt richting de avond. Voor de editie van 2026 stond Chef''Special als headliner geprogrammeerd op de hoofdpodium, met een bijzonder optreden van Ellen ten Damme samen met het Noordpoolorkest als artistiek hoogtepunt van de dag. Andere namen op het hoofdpodium waren Marc Floor, Fay, Luna en VIKTOR, terwijl op het Sena-podium onder meer Blackbriar te zien was. Op het dancepodium zorgden acts als NORDIN en Hans Glock voor de avondinvulling, en het talentpodium bracht jong Drents talent zoals Lisa Ploeger, uitgeroepen tot Talent van het Jaar bij de Popgala Noord 2026, voor het voetlicht. Die combinatie van headliner, artistiek statement en regionaal talent maakt Bevrijdingsfestival Drenthe tot een compact maar gevarieerd programma.','{pop,mixed}','Chef''Special, Ellen ten Damme, Marc Floor, Fay, Luna, VIKTOR, Blackbriar','Assen','Stadsbroek','Drenthe','2026-05-05','2026-05-05','https://www.bevrijdingsfestivaldrenthe.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 0.00, 'EUR', 'https://www.bevrijdingsfestivaldrenthe.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'bevrijdingsfestival-drenthe';

-- 21. Wilde Weide
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('wilde-weide','Wilde Weide','Wilde Weide is een relatief jong zomerfestival dat zich positioneert als een verlengd weekend vakantiegevoel, met een programmering die zich richt op het ontdekken van nieuwe, frisse liveacts gecombineerd met dansbare zomerse dj-sets. Het festival, gehouden in Eibergen op festivalterrein Weleweide, kiest bewust voor een daglicht-georienteerd programma: de nadruk ligt op de middag en vroege avond in plaats van op een klassiek nachtprogramma, wat het festival een relaxte, wat huiselijke sfeer geeft vergeleken met festivals die vooral om de avonduren draaien. Muzikaal biedt Wilde Weide een kleurrijke mix van genres: van frisse indie en synthpop tot grensverleggende hiphop, dansbare funk en reggae-invloeden, abrasieve garage rock, psychedelica en links-georienteerde house en breakbeat. Die brede maar zorgvuldig samengestelde programmering onderscheidt het festival van eendimensionale genre-festivals. Voor de editie van 2026, van vrijdag 3 tot en met zondag 5 juli, bevestigde de organisatie een line-up met onder meer De Jeugd van Tegenwoordig, MEROL, Sophie Straat en een dj-set van Pendulum, aangevuld met Sef, Jungle By Night, Hiqpy en Bente. Het festival profileert zich daarmee als een weekend waarin creativiteit en avontuur centraal staan, met een sfeer die uitnodigt tot wandelen door de natuur en ontdekken in plaats van massaal voor een podium staan. Voor bezoekers die op zoek zijn naar een kleinschaliger alternatief met een verrassende, kleurrijke programmering is Wilde Weide inmiddels een vaste waarde geworden in de zomerkalender.','{mixed,pop,electronic}','De Jeugd van Tegenwoordig, MEROL, Sophie Straat, Pendulum, Sef, Jungle By Night, Hiqpy, Bente','Eibergen','Weleweide','Gelderland','2026-07-03','2026-07-05','https://www.wildeweide.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 120.00, 'EUR', 'https://www.wildeweide.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'wilde-weide';

-- 22. Grasnapolsky
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('grasnapolsky','Grasnapolsky','Grasnapolsky is een festival dat zich nadrukkelijk profileert als ontdekfestival binnen de Nederlandse undergroundscene, met een programmering die bewust weinig gevestigde hitnamen bevat en juist ruimte biedt aan nieuwe, vaak nog onbekende artiesten uit de indie-, elektronische en experimentele muziek. Het festival vindt traditiegetrouw plaats in het Hemelvaartweekend en koos voor de editie van 2026 het voormalige Suikerunieterrein in Groningen als locatie: een rauwe, industriele plek waar verleden en creativiteit samenkomen, en die daarmee een grimmige maar sfeervolle tegenhanger vormt van de meer gepolijste festivalterreinen elders in het land. Die combinatie van een industriele setting met een scherp curatorschap geeft Grasnapolsky een underground karakter dat het festival onderscheidt van grotere, publieksgerichte evenementen. Het publiek bestaat vooral uit muziekliefhebbers die gericht zijn op ontdekking: de affiche bevat tientallen namen uit de opkomende Nederlandse en internationale scene, met acts als Ratboys, Tom Forever, Bricknasty en tientallen andere, kleinere namen verspreid over de drie festivaldagen van donderdag 14 tot en met zaterdag 16 mei. Voor 2026 koos de organisatie er bovendien bewust voor om de ticketprijzen toegankelijker te maken, in een tijd waarin veel festivals juist duurder worden, wat aansluit bij het laagdrempelige, ontdekkingsgerichte karakter van het festival. Voor bezoekers die liever nieuwe muziek ontdekken dan bekende hits meezingen, geldt Grasnapolsky als een van de belangrijkste broedplaatsen binnen de Nederlandse festivalscene.','{pop,indie,mixed}','Ratboys, Tom Forever, Bricknasty, Alexander Moto, Badminton, Kaya','Groningen','Suikerunieterrein','Groningen','2026-05-14','2026-05-16','https://www.grasnapolsky.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 45.00, 'EUR', 'https://www.grasnapolsky.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'grasnapolsky';

