-- ZeeZout-editie die kon worden teruggevonden was op 29-08-2026 (Tuinen van West). Beschrijving
-- en prijs zijn daarom generiek/geschat gehouden i.p.v. gekoppeld aan de augustus-line-up.

-- 1. DGTL Amsterdam
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('dgtl','DGTL Amsterdam','DGTL Amsterdam is een van de festivals die al sinds de oprichting in 2013 nadrukkelijk inzet op de combinatie van elektronische muziek, kunst en duurzaamheid. De line-up leunt zwaar op house en techno, met een programmering die bewust schippert tussen gevestigde namen en opkomend talent uit de undergroundscene. De editie van 2026, met als thema CTRL//BREAK, vond plaats van vrijdag 3 tot en met zondag 5 april op het industriële terrein van NDSM-werf in Amsterdam-Noord, een decor van scheepshallen en kranen dat DGTL al jaren als vaste stek gebruikt. Het festival staat bekend om zijn immersieve podiumbouw, waarbij elk stage een eigen visuele identiteit en soundsysteem krijgt, en om een boekingsbeleid dat verder kijkt dan de voor de hand liggende hoofdact. Voor 2026 stonden onder meer Armand van Helden, CamelPhat, Âme & Trikk, Jayda G, Dom Dolla, I Hate Models en Joy Orbison op de affiche, een mix van house-veteranen en techno-vernieuwers die precies past bij het brede spectrum waarmee DGTL zich onderscheidt van puur op headliners gerichte festivals. De vroegboekkaarten waren binnen een dag uitverkocht, wat aangeeft hoe gewild een ticket voor deze editie was. DGTL profileert zich nadrukkelijk als een festival met een boodschap: naast de muziek is er veel aandacht voor circulaire economie, foodconcepten en kunstinstallaties die bezoekers aan het denken zetten over de toekomst van festivals zelf. Die combinatie van scherpe muzikale curatie en een uitgesproken duurzaamheidsagenda maakt DGTL een van de weinige grote Nederlandse dance-evenementen die evenveel gewicht geeft aan het verhaal achter het festival als aan de line-up.','{electronic,techno,house}','Armand van Helden, CamelPhat, Âme & Trikk, Jayda G, Dom Dolla, I Hate Models, Joy Orbison, FJAAK','Amsterdam','NDSM-werf','Noord-Holland','2026-04-03','2026-04-05','https://www.dgtl.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 77.00, 'EUR', 'https://www.dgtl.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'dgtl';

-- 2. Dekmantel Festival
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('dekmantel','Dekmantel Festival','Dekmantel Festival groeide uit van een klein label-evenement tot een van de meest gerespecteerde house- en technofestivals ter wereld, met een programmering die nadrukkelijk niet meegaat in mainstream EDM-trends. De organisatie, ontstaan vanuit het gelijknamige platenlabel, bouwt de line-up al meer dan tien jaar op rond diggers, dj-acts en live-optredens die het verschil maken op de dansvloer in plaats van op de affiche. De editie van 2026 loopt van woensdag 29 juli tot en met zondag 2 augustus, met stadsconcerten op onder meer de Oude Kerk, Melkweg en Paradiso vooraf, gevolgd door het hoofdfestival in de Amsterdamse Bos van vrijdag tot en met zondag. Meer dan 160 artiesten staan geboekt, met uitschieters als Underground Resistance, Skrillex, CCL en het duo Helena Hauff & L.F.T., een line-up die het spectrum van klassieke Detroit-techno tot eigenzinnige hedendaagse producties bestrijkt. Kenmerkend voor Dekmantel is de bijna obsessieve aandacht voor geluidskwaliteit en de intieme schaal van de podia, ook al groeit het festival ieder jaar in omvang. Tickets zijn traditioneel binnen enkele weken uitverkocht, wat pre-registratie in de praktijk noodzakelijk maakt om verzekerd te zijn van een plek. De Amsterdamse Bos zelf, met zijn bomen en waterpartijen, vormt een groen contrast met de scherpe, soms industriële muziek die er klinkt, en dat contrast is inmiddels net zo''n handelsmerk geworden als de muziek zelf.','{electronic,house,techno}','Underground Resistance, Skrillex, CCL, Helena Hauff & L.F.T.','Amsterdam','Amsterdamse Bos','Noord-Holland','2026-07-29','2026-08-02','https://dekmantelfestival.com','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 75.00, 'EUR', 'https://dekmantelfestival.com', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'dekmantel';

-- 3. Loveland Festival
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('loveland','Loveland Festival','Loveland Festival vindt zijn oorsprong in de Amsterdamse clubscene van het begin van deze eeuw en groeide van een indoor feestreeks uit tot een van de grootste house- en technofestivals van Nederland. In 2026 viert het festival zijn 25-jarig bestaan met twee dagen vol muziek op 8 en 9 augustus in het Sloterpark, het grootste park van Amsterdam-Nieuw-West. Loveland staat bekend om een uitbundige, kleurrijke productie waarin theatrale decorstukken, interactieve kunst en verrassingselementen minstens zo belangrijk zijn als de line-up zelf, iets wat het festival onderscheidt van de wat kalere, op de muziek gerichte technofestivals in het land. De boeking voor het jubileumjaar is navenant zwaar: Chris Liebing, Speedy J, Enrico Sangiuliano, Kevin de Vries, Fatboy Slim, Jamie Jones, Joris Voorn en het legendarische duo Sasha & John Digweed staan op de affiche, aangevuld met namen als Eric Prydz en CamelPhat. Die combinatie van techno-zwaargewichten en house-iconen weerspiegelt de breedte van het genre waarin Loveland zich beweegt. Het evenement is uitsluitend toegankelijk voor bezoekers van 18 jaar en ouder en trekt van oudsher een trouw publiek dat het festival al vanaf de eerste edities volgt. Door de combinatie van een herkenbare, feestelijke visuele identiteit en een line-up die zich niet beperkt tot een subgenre, weet Loveland zich al 25 jaar staande te houden in een snel veranderende festivalmarkt.','{house,electronic}','Chris Liebing, Speedy J, Enrico Sangiuliano, Kevin de Vries, Fatboy Slim, Jamie Jones, Joris Voorn, Sasha & John Digweed, Eric Prydz, CamelPhat','Amsterdam','Sloterpark','Noord-Holland','2026-08-08','2026-08-09','https://www.lovelandfestival.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 69.00, 'EUR', 'https://www.lovelandfestival.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'loveland';

-- 4. Dance Valley
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('dance-valley','Dance Valley','Dance Valley behoort tot de oudste dance-evenementen van Nederland en speelt al sinds 1995 een rol in de ontwikkeling van de Nederlandse festivalcultuur, met Spaarnwoude in Velsen-Zuid als vertrouwde vaste locatie. Waar het festival ooit vooral bekendstond om trance en de opkomst van de Nederlandse EDM-scene, is de line-up inmiddels breder getrokken richting house, techno en mainstage-dance, zonder de nostalgische kern uit het oog te verliezen. De editie van 8 augustus 2026 trekt naar verwachting rond de 40.000 bezoekers en zet met Calvin Harris en Hardwell twee internationale grootheden centraal, aangevuld met een reeks namen die de geschiedenis van het festival recht doen: Ferry Corsten, Charly Lownoise & Mental Theo, Markus Schulz, Quintino, Gregor Salto en Chuckie. Die mix van klassiekers uit de jaren negentig en actuele hitmakers maakt Dance Valley een festival waar meerdere generaties dancefans samenkomen. Het decor van Spaarnwoude, een uitgestrekt recreatiegebied tussen Amsterdam en Haarlem, biedt ruimte voor meerdere grote podia en een festivalopzet die nadrukkelijk op massabeleving is gericht, met veel aandacht voor lichtshows en podiumproducties op grote schaal. Na jaren van wisselende programmering en een korte onderbreking heeft Dance Valley de afgelopen edities weer nadrukkelijk de ambitie getoond om terug te keren als een van de grootste eendaagse dance-evenementen van het land.','{house,electronic,techno}','Calvin Harris, Hardwell, Ferry Corsten, Markus Schulz, Quintino, Gregor Salto, Chuckie','Velsen-Zuid','Spaarnwoude','Noord-Holland','2026-08-08','2026-08-08','https://www.dancevalley.com','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 75.00, 'EUR', 'https://www.dancevalley.com', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'dance-valley';

-- 5. Draaimolen Festival
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('draaimolen','Draaimolen Festival','Draaimolen heeft zich in relatief korte tijd ontwikkeld tot een van de meest geliefde boutique-technofestivals van Nederland, met een programmering die weloverwogen kiest voor ontdekking boven headliners. Het festival is bekend om zijn sfeervolle, bosrijke setting op Landgoed Huis ter Heide bij Tilburg, waar podia organisch zijn ingepast tussen de bomen en een sterke visuele identiteit minstens zo veel indruk maakt als de muziek. In 2026 vindt de editie plaats op 4 en 5 september, opnieuw op het zogeheten MOB-complex. Op het moment van schrijven was de volledige line-up nog niet aangekondigd, wat past bij de werkwijze van de organisatie: line-ups worden vaak relatief laat en in fases onthuld, om de nadruk te leggen op de algehele ervaring in plaats van op individuele namen. Wat wel bekend is, is dat de kaartverkoop goed loopt; van bepaalde ticketcategorieën, zoals late vrijdagkaarten, was er nog beperkt aanbod. Draaimolen onderscheidt zich verder door een sterke, hechte community rond het festival, met bezoekers die jaar na jaar terugkeren vanwege de intieme schaal en de zorgvuldige aandacht voor detail in decor, geluid en routing over het terrein. Voor liefhebbers van pure, undergroundgerichte techno geldt Draaimolen inmiddels als een van de betrouwbaarste namen in de Nederlandse festivalagenda, ook al blijft de line-up tot kort voor de editie vaak nog grotendeels een verrassing.','{techno,electronic}','Tilburg','Landgoed Huis ter Heide','Noord-Brabant','2026-09-04','2026-09-05','https://www.draaimolen.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 110.00, 'EUR', 'https://www.draaimolen.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'draaimolen';

-- 6. Verknipt Festival
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('verknipt-festival','Verknipt Festival','Verknipt Festival groeide in enkele jaren tijd uit van een clubavond in Utrecht tot een van de grootste technofestivals van Nederland, met een editie die zich nadrukkelijk richt op de hardere, dansvloergerichte kant van het genre. De editie van 2026, met als thema Breaking Patterns, vond plaats op 6 en 7 juni bij de Strijkviertelplas in Utrecht en bood meer dan 36 artiesten verdeeld over zes podia. De line-up bestond grotendeels uit namen uit de internationale technoscene die niet per se breed bekend zijn bij het grote publiek, maar binnen de genrescene juist veel aanzien genieten, zoals AREA ØNE, Justin Jay, Hurts en Fantasm. Die keuze voor scherpe, op de scene gerichte curatie in plaats van mainstream hoofdacts is precies wat Verknipt onderscheidt van bredere dance-festivals. Kaarten voor de zaterdag waren ruim voor de editie al uitverkocht, wat de groeiende populariteit van het festival onderstreept; instapprijzen voor het weekend lagen rond de 64 euro. De bezoekersleeftijd ligt met een minimumleeftijd van 18 jaar en een streng identificatiebeleid iets hoger dan bij veel andere festivals, wat aansluit bij het wat serieuzere, op de muziek gerichte karakter van het evenement. Verknipt combineert een industriële, functionele podiumopzet met een geluidskwaliteit die veel recensenten roemen, en bouwt daarmee gestaag verder aan een reputatie als vaste waarde in de Nederlandse technokalender.','{techno,house}','AREA ØNE, Justin Jay, Hurts, Fantasm, JALO, KARAH, Winson, Nyco','Utrecht','Strijkviertel','Utrecht','2026-06-06','2026-06-07','https://www.verknipt.org','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 64.09, 'EUR', 'https://www.verknipt.org', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'verknipt-festival';

-- 7. Soenda Festival
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('soenda','Soenda Festival','Soenda is een eendaags house- en technofestival dat wordt georganiseerd in de Ruigenhoekse polder nabij Utrecht en zich in korte tijd heeft ontwikkeld tot een gerespecteerd platform voor zowel gevestigde namen als aanstormend talent binnen de undergroundscene. De editie van 30 mei 2026 werd, net als voorgaande jaren, ruim voor de festivaldag al uitverkocht, tegen een ticketprijs van 69,90 euro. De line-up bevatte artiesten als AUTOFLOWER, het duo Afem Syko & Cynthia Spiering, SNTS, DYEN, Eva Vrijdag, Lisa Korver, Partiboi69 en Novah, een programmering die bewust kiest voor diepgang binnen house en techno in plaats van voor een handvol grote namen. Het festival is te bereiken via een pendelbusdienst vanaf Utrecht Centraal, wat de wat afgelegen ligging van het terrein compenseert en tegelijk bijdraagt aan het besloten, community-gevoel dat bezoekers aan Soenda toeschrijven. In tegenstelling tot de grote, breed geprogrammeerde festivals in de regio, houdt Soenda het aantal podia en artiesten bewust behapbaar, met als resultaat een programmering waarin elke set de aandacht krijgt die hij verdient. De combinatie van een korte, drukke festivaldag van 12.00 tot 23.00 uur en een scherp geselecteerde line-up heeft Soenda de afgelopen jaren een vaste plek bezorgd in de agendas van technoliefhebbers die net iets meer verdieping zoeken dan de grote namen alleen.','{techno,electronic}','AUTOFLOWER, Afem Syko & Cynthia Spiering, SNTS, DYEN, Eva Vrijdag, Lisa Korver, Partiboi69, Novah','Utrecht','Rhijnauwen','Utrecht','2026-05-30','2026-05-30','https://www.soenda.com','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 69.90, 'EUR', 'https://www.soenda.com', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'soenda';

-- 8. A State of Trance Festival
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('a-state-of-trance','A State of Trance Festival','A State of Trance Festival is het fysieke uitvloeisel van het gelijknamige radioprogramma en de wereldwijde merknaam van dj-producer Armin van Buuren, en geldt al jaren als het belangrijkste podium voor de internationale trancegemeenschap. De editie van 2026, gehouden op 27 en 28 februari in de Jaarbeurs Utrecht, markeerde het 25-jarig bestaan van het ASOT-concept en werd dienovereenkomstig groots aangepakt. Van Buuren was op beide dagen het middelpunt, met onder meer een uitgebreide soloset op vrijdag en een gezamenlijk optreden met Oliver Heldens en Maddix op zaterdag. Overige namen op de affiche waren Cosmic Gate, Rank 1, Aly & Fila, Ferry Corsten en Giuseppe Ottaviani, stuk voor stuk artiesten die decennialang meebouwden aan het trancegenre. Wat ASOT onderscheidt van andere grote dance-evenementen is de intensiteit van de fanbase: bezoekers reizen vanuit de hele wereld naar Utrecht specifiek voor dit weekend, en VIP-tickets waren dan ook ruim voor de editie al uitverkocht. De productie leunt zwaar op een indoor, arena-achtige setting met grootschalige lichtshows en een geluidssysteem dat is afgestemd op de emotionele, melodieuze kant van trance. Voor liefhebbers van het genre is ASOT niet zomaar een festival, maar een jaarlijkse pelgrimage naar het hart van de trancecultuur, met een sfeer die bekendstaat als warmer en gemeenschapsgerichter dan bij veel andere grootschalige dance-evenementen.','{electronic,house}','Armin van Buuren, Oliver Heldens, Maddix, Cosmic Gate, Rank 1, Aly & Fila, Ferry Corsten, Giuseppe Ottaviani','Utrecht','Jaarbeurs','Utrecht','2026-02-27','2026-02-28','https://www.astateoftrance.com','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 129.00, 'EUR', 'https://www.astateoftrance.com', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'a-state-of-trance';

-- 9. Free Your Mind Arnhem
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('free-your-mind-arnhem','Free Your Mind Arnhem','Free Your Mind Arnhem is de oudste en meest gevestigde editie van het Free Your Mind-merk en wordt gehouden op de Stadsblokken, het eilandgebied in de Rijn bij Arnhem dat historisch bekend is van de Slag om Arnhem tijdens de Tweede Wereldoorlog. Die geschiedenis staat in schril contrast met het hedendaagse, op techno en house gerichte programma van het festival. De editie van 6 en 7 juni 2026 bracht een zware internationale line-up naar de stad, met Eric Prydz, Boris Brejcha, Paul Kalkbrenner, Don Diablo, Innellea, Reinier Zonneveld, Pan-Pot, Seth Troxler en The Martinez Brothers, een combinatie van mainstage-namen en meer op de underground gerichte artiesten die precies de breedte van het festival illustreert. Free Your Mind Arnhem wordt doorgaans over twee dagen georganiseerd, met openingstijden die tot laat in de avond doorlopen, en trekt een publiek dat zowel voor de grote techno-acts als voor de intieme podia met opkomend talent komt. Het festival hanteert een strikte leeftijdsgrens van 18 jaar en een zerotolerancebeleid, wat aansluit bij het imago van een volwassen, op de muziek gerichte techno-ervaring. Door de combinatie van een historisch beladen locatie, een zwaar internationaal geboekte line-up en een goed georganiseerde productie heeft Free Your Mind Arnhem zich stevig gevestigd als een van de belangrijkste techno-evenementen van het oosten van Nederland.','{techno,electronic}','Eric Prydz, Boris Brejcha, Paul Kalkbrenner, Don Diablo, Innellea, Reinier Zonneveld, Pan-Pot, Seth Troxler, The Martinez Brothers','Arnhem','Meinerswijk','Gelderland','2026-06-06','2026-06-07','https://www.freeyourmindfestival.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 89.00, 'EUR', 'https://www.freeyourmindfestival.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'free-your-mind-arnhem';

-- 10. Free Your Mind Groningen
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('free-your-mind-groningen','Free Your Mind Groningen','Free Your Mind Groningen is de noordelijke zusteditie van het gevestigde Arnhemse festival en biedt een compactere, eendaagse versie van hetzelfde concept, gehouden op de drafbaan in het Stadspark van Groningen. De editie van 25 juli 2026 combineerde gevestigde techno- en housenamen met een aantal opkomende artiesten uit de Nederlandse scene, waaronder Ben Böhmer, Stephan Bodzin, Reinier Zonneveld, Hannah Laing, Benny Rodrigues en Michel de Hey. Die programmering laat zien dat het festival, ondanks de kleinere schaal ten opzichte van de Arnhemse editie, weinig inboet op de kwaliteit van de boekingen. Tickets voor de eerste verkoopfase gingen weg vanaf 46 euro, een prijs die het festival toegankelijker maakt dan veel vergelijkbare eendaagse techno-evenementen in de Randstad. Groningen ligt buiten de gebruikelijke festivalregio rond Amsterdam en Utrecht, en Free Your Mind speelt daar bewust op in door zich te profileren als het techno-evenement van het Noorden, waarmee het een publiek bedient dat anders vaak een lange reis zou moeten maken voor een vergelijkbare line-up. De combinatie van een groene, goed bereikbare locatie in het Stadspark en een scherp geprijsd toegangsbewijs maakt dit een van de laagdrempeligere techno-festivals in de Nederlandse agenda, zonder dat dit ten koste gaat van de kwaliteit van de line-up.','{techno,electronic}','Ben Böhmer, Stephan Bodzin, Reinier Zonneveld, Hannah Laing, Benny Rodrigues, Michel de Hey','Groningen','Stadspark','Groningen','2026-07-25','2026-07-25','https://www.freeyourmindfestival.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 46.00, 'EUR', 'https://www.freeyourmindfestival.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'free-your-mind-groningen';

-- 11. Welcome To The Future
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('welcome-to-the-future','Welcome To The Future','Welcome To The Future is historisch een van de invloedrijkste Nederlandse techno- en housefestivals, met wortels die teruggaan tot 2007 in de natuurlijke omgeving van Het Twiske bij Amsterdam. Het festival bouwde een reputatie op als kraamkamer voor Nederlands technotalent en als een van de eerste multi-stage bosfestivals in het land, met een programmering over zes podia die de nadruk legde op sfeer en ontdekking. Na de laatst bevestigde editie op de vertrouwde Twiske-locatie in 2022 is er weinig concrete, verifieerbare informatie beschikbaar over een vervolg. Voor deze database is een editie in 2026 opgenomen op basis van een vermeende locatie in Olterterp bij Beetsterzwaag in Friesland, maar bij nader onderzoek kon dit niet worden bevestigd: de officiële website van het festival toont geen actieve inhoud en er zijn geen betrouwbare bronnen gevonden die een concrete datum, line-up of ticketprijs voor deze editie bevestigen. Gezien deze onzekerheid wordt deze vermelding met nadrukkelijke voorzichtigheid gepresenteerd; redacteuren doen er goed aan de actuele status rechtstreeks bij de organisatie te verifiëren voordat verdere content of ticketverkoop hieraan wordt gekoppeld. Mocht de editie alsnog doorgaan, dan ligt het voor de hand dat het festival, gezien zijn geschiedenis, opnieuw zal inzetten op een combinatie van techno, house en een sterk naar binnen gerichte, sfeervolle productie.','{techno,house}','Beetsterzwaag','Olterterp','Friesland','2026-04-25','2026-04-25','https://www.wttf.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', null, 'EUR', 'https://www.wttf.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'welcome-to-the-future';

-- 12. ZeeZout Festival
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('zeezout','ZeeZout Festival','ZeeZout Festival is een terugkerende reeks dagfestivals in het westelijke deel van Amsterdam, met een programmering die stevig leunt op house en techno uit zowel de gevestigde als de opkomende garde. De naam verwijst naar de ligging nabij het water, en het festival wisselt door het jaar heen van edities op locaties in de omgeving van Nieuwe Diep en de Tuinen van West. Voor de editie die in deze database is opgenomen, gepland op 13 juni 2026, kon geen specifieke, bevestigde line-up worden teruggevonden; wel is bekend dat vergelijkbare edities van het festival in 2026 line-ups presenteerden met artiesten als Carista, Mall Grab, Identified Patient en Lisa Korver, en tickets voor die edities rond de 49 euro kostten. ZeeZout onderscheidt zich door een relatief intieme opzet vergeleken met de grote Amsterdamse festivals, met een publiek dat vooral bestaat uit liefhebbers van pure house en techno zonder al te veel poespas eromheen. Het evenement is uitsluitend toegankelijk voor bezoekers van 18 jaar en ouder en wordt door de doelgroep vooral gewaardeerd om de combinatie van scherpe curatie, een overzichtelijke schaal en een prettige buitenlocatie. Doordat ZeeZout meerdere keren per jaar wordt georganiseerd, functioneert het festival voor veel Amsterdamse dansliefhebbers als vast terugkerend hoogtepunt in de agenda, ook wanneer een specifieke editie qua line-up nog niet volledig is uitgekristalliseerd.','{house,electronic}','Amsterdam','Nieuwe Diep','Noord-Holland','2026-06-13','2026-06-13','https://www.zeezoutfestival.nl','past',false);

