from festivals where slug = 'zeezout';

-- 13. Into The Woods
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('into-the-woods','Into The Woods','Into The Woods ontstond in 2010 als initiatief van een groep vrienden uit Amersfoort, onder wie de broers Siep en Sijmen Stronks, Paul Niezen en Timo Spruitenburg, geïnspireerd door het Utrechtse Stekkerfest in de Voorveldse Polder. Wat begon als een kleinschalige editie in het Openluchttheater groeide uit tot een gevestigd multi-genre festival dat inmiddels ook een aparte editie tijdens Amsterdam Dance Event kent. De hoofdversie in het Amersfoortse bosgebied Birkhoven, met podia verscholen tussen de bomen, blijft het hart van het concept: een combinatie van techno, house en disco, verrijkt met kunstinstallaties die het bos tijdens het festivalweekend in een sprookjesachtig decor veranderen. De editie van 18 en 19 september 2026 bouwt voort op die traditie en was bij aankondiging al snel uitverkocht. Into The Woods heeft in de loop der jaren een trouwe achterban opgebouwd die het festival vooral waardeert om de sfeer en de zorgvuldige aankleding van het terrein, eerder dan om een enkele grote hoofdact. Het tienjarig jubileum in 2019 onderstreepte hoezeer het festival is uitgegroeid van een lokaal experiment tot een vaste waarde in de Nederlandse festivalkalender, met een positionering die zich richt op ontdekking, artistieke beleving en een breed genre-aanbod binnen de elektronische muziek.','{house,techno,electronic}','Amersfoort','Nimmerdor','Utrecht','2026-09-18','2026-09-19','https://www.intothewoodsfestival.nl','sold_out',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 79.00, 'EUR', 'https://www.intothewoodsfestival.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'into-the-woods';

-- 14. Mystic Garden Festival
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('mystic-garden-festival','Mystic Garden Festival','Mystic Garden Festival profileert zich als een van de meer intieme boutique-weekendfestivals binnen de Nederlandse house- en technoscene, gehouden in de bosrijke omgeving van het Horsterwold bij Zeewolde met een bewust beperkte capaciteit van ongeveer 10.000 bezoekers. Het concept draait om vijf verschillende podia verspreid door het bos, elk met een eigen sfeer, en een programmering die techno, tech-house, trance en melodische house combineert tot een driedaagse ervaring die zich nadrukkelijk onderscheidt van de grotere, massaal geprogrammeerde festivals in de regio. De organisatie maakte in mei 2026 bekend dat de editie van 21 tot en met 23 augustus niet doorgaat: er ontbrak een gezond financieel fundament en toekomstperspectief om de editie verantwoord te laten plaatsvinden. Ticketkopers kregen de keuze tussen terugbetaling of een voucher ter waarde van 110 procent van de aankoopprijs, geldig voor een toekomstige editie. De organisatie liet weten in 2027 te hopen terug te keren, zonder daar al een concrete datum aan te verbinden.','{house,electronic}','Zeewolde','Spiegelplas / Wuivend Riet','Flevoland','2026-08-21','2026-08-23','https://www.mysticgardenfestival.nl','cancelled',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', null, 'EUR', 'https://www.mysticgardenfestival.nl', 'unknown', '2026-07-03T09:00:00Z'
from festivals where slug = 'mystic-garden-festival';

-- 15. Audio Obscura
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('audio-obscura','Audio Obscura','Audio Obscura is een Rotterdams dagfestival dat wordt gehouden in de Van Nelle Fabriek, een voormalig industrieel complex met UNESCO-werelderfgoedstatus dat de organisatie ombouwt tot een decor voor house en techno. Die combinatie van monumentale architectuur en scherp geprogrammeerde elektronische muziek is het belangrijkste onderscheidende kenmerk van het festival binnen de Rotterdamse dance-agenda. De editie van 29 augustus 2026 liep van 16.00 tot 22.30 uur en bracht een line-up met onder meer Chris Stussy, Honey Dijon, Folamour, Prospa, Max Dean en de back-to-back-sets van DJ Gigola met Chloé Caillet, aangevuld met Marsolo. De reguliere tickets waren ruim voor de festivaldag al uitverkocht, wat past bij de groeiende reputatie van Audio Obscura als een van de beter gecureerde house- en technofestivals van het land. Van elk ticket ging bovendien een bijdrage naar het behoud van de Van Nelle Fabriek, waarmee het festival zijn locatie expliciet met de bezoekers deelt als gezamenlijke verantwoordelijkheid. Het compacte tijdsbestek van een middag en avond, in combinatie met de industriële setting en een line-up die inzet op kwaliteit boven kwantiteit, geeft Audio Obscura een net iets andere uitstraling dan de vele buitenfestivals in parken en polders: intiemer, urbaner en nadrukkelijker verbonden met de architectuur van de stad.','{techno,house,electronic}','Chris Stussy, Honey Dijon, Folamour, Prospa, Max Dean, DJ Gigola, Chloé Caillet, Marsolo','Rotterdam','Kralingse Bos','Zuid-Holland','2026-08-29','2026-08-29','https://www.audioobscura.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 74.95, 'EUR', 'https://www.audioobscura.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'audio-obscura';

-- 16. A Day At The Park
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('a-day-at-the-park','A Day At The Park','A Day At The Park is een terugkerend dagfestival in het Kralingse Bos, het grote stadspark van Rotterdam, en profileert zich als een toegankelijke maar muzikaal serieuze house- en technodag voor een breed publiek. De editie van 13 september 2026 loopt van 14.00 tot middernacht en biedt een line-up met onder meer Claptone, Shermanology, Michel de Hey, Philou Louzolo en de duos Eva Vrijdag & Fiene en Baggi & Ammé, een combinatie van internationale house-acts en Nederlandse dj-acts uit de bredere Rotterdamse scene. De sfeer van het festival wordt sterk bepaald door de groene omgeving van het park, waar meerdere podia tussen het groen zijn verwerkt zonder dat het festival de schaal van een grootschalig evenement aanneemt. Tickets in de laatste beschikbare categorie kosten 55 euro exclusief servicekosten, wat het festival prijstechnisch in de middenmoot van de Nederlandse eendaagse house-festivals plaatst. A Day At The Park wordt door de lokale scene gewaardeerd als een van de vaste hoogtepunten van het Rotterdamse zomerseizoen, met een programmering die bewust net iets breder trekt dan pure underground house door ook meer bekende namen als Claptone en Shermanology een podium te geven, zonder de herkenbare, ontspannen sfeer van een parkfestival te verliezen.','{house,electronic}','Claptone, Shermanology, Michel de Hey, Philou Louzolo, Eva Vrijdag, Fiene, Baggi, Ammé','Rotterdam','Kralingse Bos','Zuid-Holland','2026-09-13','2026-09-13','https://www.adayatthepark.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 55.00, 'EUR', 'https://www.adayatthepark.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'a-day-at-the-park';

-- 17. Lakedance
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('lakedance','Lakedance','Lakedance is een meerdaags georganiseerd festivalconcept aan het water van Aquabest, het recreatiegebied bij Best in de buurt van Eindhoven, met edities in zowel mei als augustus. De editie van 16 mei 2026 bood over zeven podia een breed spectrum aan stijlen binnen house, tech house, techno, guilty pleasure en freestyle, met een line-up waarin Jay Hardway, Mesto, Sick Individuals, Lucas & Steve, Michel De Hey en Ferreck Dawn de belangrijkste namen waren. Die genrebreedte is precies wat Lakedance onderscheidt van festivals die zich puur op techno of puur op mainstage-EDM richten: bezoekers kunnen op een dag wisselen tussen een tech house-set en een uitbundig gastfeestje op de guilty pleasure-stage. De ligging aan het water van Aquabest zorgt voor een herkenbare, zomerse sfeer met strandkarakter, waarbij het festivalterrein zich rond de plas uitstrekt en podia deels los van elkaar zijn gepositioneerd. Reguliere tickets voor de editie van mei waren verkrijgbaar vanaf 45 euro, met daarnaast diverse VIP- en combi-opties voor bezoekers die ook de augustuseditie willen bijwonen. Lakedance trekt vooral een jong publiek uit Brabant en omstreken en heeft zich in de regio ontwikkeld tot een vast onderdeel van de festivalkalender rond zowel de meivakantie als de zomer.','{house,electronic}','Jay Hardway, Mesto, Sick Individuals, Lucas & Steve, Michel De Hey, Ferreck Dawn','Best','Recreatieplas Aquabest','Noord-Brabant','2026-05-16','2026-05-16','https://www.lakedance.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 45.00, 'EUR', 'https://www.lakedance.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'lakedance';

-- 18. WiSH Outdoor
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('wish-outdoor','WiSH Outdoor','WiSH Outdoor onderging voor de editie van 2026 een van de grootste veranderingen in zijn bestaan: na jaren op het vertrouwde terrein bij Beek en Donk verhuisde het festival naar het terrein van de Bavariabrouwerij in Lieshout. Die verhuizing ging gepaard met een inhoudelijke koerswijziging, waarbij het festival voor het eerst per dag een ander muzikaal karakter aanhoudt: de vrijdag staat in het teken van Nederlandstalige meezingers en feestacts, terwijl zaterdag is gereserveerd voor elektronische live-acts, popartiesten en dj-sets die het bredere house- en electronic-spectrum bestrijken. Deze opzet maakt WiSH een van de weinige festivals in de Nederlandse agenda die bewust meerdere doelgroepen binnen een weekend bedient, van feestgangers tot doorgewinterde dance-liefhebbers. De editie van 3 tot en met 5 juli 2026 was met de vroegboek- en loyaliteitskaarten al ver voor de festivaldagen goeddeels uitverkocht, met dagkaarten die vanaf 40 euro begonnen en een driedaags combiticket van 95 euro. Het festival hanteert op vrijdag en zaterdag een leeftijdsgrens van 18 jaar, terwijl de zondag toegankelijk is voor alle leeftijden, wat aansluit bij het bredere, meer diverse karakter dat de organisatie met de nieuwe locatie en opzet nastreeft. Met de stap naar Lieshout zet WiSH nadrukkelijk in op een nieuwe fase waarin schaal, diversiteit en een fris decor centraal staan.','{house,electronic,mixed}','Beek en Donk','Bult van Beek','Noord-Brabant','2026-07-03','2026-07-05','https://www.wishoutdoor.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 40.00, 'EUR', 'https://www.wishoutdoor.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'wish-outdoor';

-- 19. Solar Weekend
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('solar-weekend','Solar Weekend','Solar Weekend is een van de langstlopende meerdaagse festivals van Limburg en wordt sinds jaar en dag georganiseerd aan de Maasplassen bij Roermond, met de halte Hatenboer/De Weerd als vaste toegangspoort tot het terrein. Het festival profileert zich met de slogan Built on Creativity en combineert al sinds de beginjaren een brede mix van genres, van house en electronic tot urban en hiphop, wat resulteert in een opvallend divers publiek voor een festival van dit formaat. De editie van 30 juli tot en met 2 augustus 2026 bracht onder meer Broederliefde, Bizzey, Lijpe, Lil Kleine, La Fuente, Yellow Claw en Monica Geuze samen met namen uit de housescene als Benny Rodrigues, Ferreck Dawn en Gregor Salto, een combinatie die laat zien hoe het festival bewust de grenzen tussen genres opzoekt in plaats van zich tot een stijl te beperken. Tickets waren verkrijgbaar vanaf 72,50 euro in de vroegboekfase, oplopend tot 165 euro voor de duurdere categorieën, met prijsstijgingen na 5 april. Kamperen is een vast onderdeel van de Solar-ervaring, met een campingcultuur die net zo bepalend is voor de sfeer als de line-up zelf. Door de ligging aan het water en de mix van muziekstijlen weet Solar Weekend al jarenlang een groot, trouw publiek uit de regio en daarbuiten te trekken naar een weekend dat draait om creativiteit, ontspanning en een brede muzikale programmering.','{house,electronic,mixed}','Broederliefde, Bizzey, Lijpe, Lil Kleine, La Fuente, Yellow Claw, Monica Geuze, Benny Rodrigues, Ferreck Dawn, Gregor Salto','Roermond','Hatenboer','Limburg','2026-07-30','2026-08-02','https://solarweekend.com','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 72.50, 'EUR', 'https://solarweekend.com', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'solar-weekend';

-- 20. Wildeburg
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('wildeburg','Wildeburg','Wildeburg presenteert zichzelf nadrukkelijk niet als een gewoon festival maar als een eigen universum, gevestigd in het Kuinderbos bij Kraggenburg in de Noordoostpolder. Het concept draait om een ononderbroken programmering van dagen en nachten, waarin techno wordt afgewisseld met eclectische live-acts en wereldmuziekinvloeden, verspreid over creatief vormgegeven podia die verscholen liggen tussen de bomen. De editie van 2026 loopt van 10 tot en met 12 juli, met camping die al eerder open kan gaan voor bezoekers die het volledige, meerdaagse avontuur willen meemaken. De vraag naar tickets overstijgt al jaren het beschikbare aanbod, waardoor de organisatie werkt met een lotingsysteem: geïnteresseerden melden zich aan en worden vervolgens willekeurig geselecteerd voor de mogelijkheid om een weekendticket te kopen, wat de druk op de verkoop eerlijker verdeelt. Een weekendticket kost 330 euro inclusief 15 euro statiegeld voor onder meer bekers. De line-up bevat namen als Jembaa Groove, Florence Adooni, Timmerman, Lucky Done Gone en Og Karin, een programmering die verder reikt dan pure techno en ook Afrikaanse en live-georiënteerde muziek een plek geeft. Die combinatie van schaarste, een sterk uitgewerkt sfeerconcept en een muzikaal avontuurlijke koers heeft Wildeburg in korte tijd tot een van de meest gewilde boutique-festivals van Nederland gemaakt.','{electronic,house}','Jembaa Groove, Florence Adooni, Timmerman, Lucky Done Gone, Og Karin','Kraggenburg','Kuinderbos','Flevoland','2026-07-10','2026-07-12','https://www.wildeburg.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 330.00, 'EUR', 'https://www.wildeburg.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'wildeburg';

-- 21. Lente Kabinet Festival
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('lente-kabinet','Lente Kabinet Festival','Lente Kabinet Festival is het voorjaarsfestival van het Dekmantel-collectief en biedt op kleinere schaal dezelfde muzikale filosofie: een eclectische mix van house, techno en disco, gecombineerd met kunst en cultuur, in de natuurlijke omgeving van Het Twiske bij Oostzaan. De editie van 23 en 24 mei 2026 bracht een line-up met onder meer Call Super, Seth Troxler, Chaos In The CBD, Shanti Celeste, DJ EZ, Goldie, Honey Dijon, Job Jobse en Young Marco, aangevuld met Chris Stussy en de Nederlandse acts Sef en Sophie Straat, een programmering die de internationale dansvloercultuur combineert met binnenlands talent. Dagtickets voor de goedkoopste categorie kostten 70,80 euro, oplopend tot 91,80 euro voor de laatst beschikbare kaarten, wat aangeeft hoe snel de vraag de beschikbare capaciteit overstijgt. Net als het grote festival in de Amsterdamse Bos was Lente Kabinet ruim voor de festivaldagen uitverkocht. De combinatie van een zorgvuldig samengestelde line-up, een groene, waterrijke locatie en de sterke reputatie van het Dekmantel-merk maakt Lente Kabinet een van de meest gewilde voorjaarsafspraken binnen de Nederlandse house- en technoscene, ondanks de bescheidener schaal ten opzichte van het hoofdfestival in de zomer.','{house,techno,electronic}','Call Super, Seth Troxler, Chaos In The CBD, Shanti Celeste, DJ EZ, Goldie, Honey Dijon, Job Jobse, Young Marco, Chris Stussy','Oostzaan','Recreatiegebied Het Twiske','Noord-Holland','2026-05-23','2026-05-24','https://www.lentekabinet.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 70.80, 'EUR', 'https://www.lentekabinet.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'lente-kabinet';

-- 22. Geheime Liefde
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('geheime-liefde','Geheime Liefde','Geheime Liefde onderscheidt zich binnen de Nederlandse festivalagenda door een strikt geheimhoudingsbeleid rond de line-up, die tot op de festivaldag zelf niet wordt vrijgegeven. Het festival wordt georganiseerd samen met XSENSE op Fort bij Vechten in Bunnik, een negentiende-eeuws fort met bunkers, tunnels en groene wallen dat een sfeervol, historisch decor biedt voor de vijf podia die het terrein rijk is. De editie van 2 mei 2026 was met een maximale capaciteit van 5.000 bezoekers en een programmering van house, deephouse, techno, urban en EDM ruim voor de festivaldag al volledig uitverkocht, waarbij doorverkoopplatformen als TicketSwap de enige veilige manier waren om alsnog aan een kaart te komen. Het geheimzinnige karakter van het festival, dat ook doorwerkt in de naam en de communicatie richting bezoekers, zorgt voor een extra laag beleving: bezoekers weten vooraf niet precies wie ze gaan zien, wat de verrassing en het gezamenlijke ontdekken tijdens het festival benadrukt. De minimumleeftijd van 18 jaar en de compacte schaal van het evenement dragen bij aan een besloten, intieme sfeer die afwijkt van de grotere, breed aangekondigde festivals in de regio Utrecht. Geheime Liefde bewijst daarmee dat een festival ook zonder vooraf bekende sterren een sterke aantrekkingskracht kan hebben.','{house,electronic}','Bunnik','Fort bij Vechten','Utrecht','2026-05-02','2026-05-02','https://www.geheimeliefde.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 55.00, 'EUR', 'https://www.geheimeliefde.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'geheime-liefde';

-- 23. Awakenings Upclose
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('awakenings-upclose','Awakenings Upclose','Awakenings Upclose is de intiemere zusteditie van het internationaal vermaarde technomerk Awakenings en wordt gehouden in Houtrak, onderdeel van het Spaarnwoude-recreatiegebied, op loop- en fietsafstand van een pendelbusverbinding vanaf Sloterdijk. Waar het hoofdfestival van Awakenings in de zomer draait om een enorme schaal en meerdere grote podia, kiest Upclose bewust voor een compacter format met meer dan 90 techno-dj''s verspreid over kleinere, dichter bij elkaar gelegen podia. De editie van 16 en 17 mei 2026 bracht onder meer Ben Klock, Ellen Allien en Nina Kraviz samen, aangevuld met tientallen back-to-back-sets en verrassingsoptredens die kenmerkend zijn voor het format. Die opzet, met legendarische techno-acts in een kleinschaligere setting, geeft bezoekers een gevoel van nabijheid tot de dj''s dat op het grote festival minder goed te realiseren is. Awakenings Upclose wordt binnen de Nederlandse technoscene beschouwd als een van de meest kwalitatief hoogstaande evenementen van het jaar, precies omdat de organisatie de schaal bewust klein houdt terwijl de line-up qua niveau nauwelijks onderdoet voor het hoofdfestival. De combinatie van uitgebreide, gedetailleerde tijdschema''s per podium en een schaal die intimiteit boven massaliteit stelt, maakt Upclose voor veel technoliefhebbers een favoriete afspraak in het festivaljaar.','{techno,electronic}','Ben Klock, Ellen Allien, Nina Kraviz','Velsen-Zuid','Spaarnwoude','Noord-Holland','2026-05-16','2026-05-17','https://www.awakenings.com','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 95.00, 'EUR', 'https://www.awakenings.com', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'awakenings-upclose';

