-- 1. Intents Festival
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('intents-festival','Intents Festival','Intents Festival is een van de grootste hardstyle-evenementen van Nederland en vindt sinds de oprichting halverwege de jaren 2000 jaarlijks plaats in Oisterwijk, in de bossen van De Kaaistoep in Noord-Brabant. Het festival heeft zich ontwikkeld tot een driedaags evenement met camping (IntentsCity) waar duizenden bezoekers uit binnen- en buitenland samenkomen. Wat Intents onderscheidt van andere hardstyle-festivals is de uitgebreide onderverdeling in subgenres: meer dan tien verschillende gebieden zijn gewijd aan specifieke stijlen binnen de harder styles, van melodische hardstyle tot de snelste tempo''s van uptempo hardcore. Hierdoor kunnen bezoekers hun avond volledig naar eigen smaak inrichten, in plaats van dat alles op een mainstage samenkomt. De natuurlijke, bosrijke setting van De Kaaistoep geeft het festival een herkenbare sfeer die afwijkt van de kale evenemententerreinen waar veel dance-festivals plaatsvinden: paden tussen de bomen, verrassende doorkijkjes naar podia en een organische indeling van het terrein. Intents trekt een trouwe internationale schare fans die het festival als hoogtepunt van hun hardstyle-kalender beschouwen, mede dankzij de reputatie op het gebied van productie, licht en geluid. Naast het hoofdprogramma is er in de loop der jaren steeds meer aandacht gekomen voor entertainment naast de muziek, met een eigen festivalstad vol activiteiten voor bezoekers die op de camping verblijven. Voor de editie van 2026, gehouden van 5 tot en met 7 juni, bood de organisatie zowel losse dag- als weekendtickets aan, met extra opties voor toegang tot IntentsCity en VIP-decks bij het mainstage. Door de combinatie van schaal, sfeer en genre-diversiteit geldt Intents als een van de belangrijkste graadmeters binnen de Nederlandse hardstylescene.','{hardstyle}','Oisterwijk','De Kaaistoep','Noord-Brabant','2026-06-05','2026-06-07','https://www.intentsfestival.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 70.00, 'EUR', 'https://www.intentsfestival.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'intents-festival';

-- 2. REBiRTH Festival
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('rebirth-festival','REBiRTH Festival','REBiRTH Festival groeide in relatief korte tijd uit tot een van de grotere driedaagse festivals binnen de hardere dansmuziek en trekt inmiddels meer dan 50.000 bezoekers naar het terrein Duinenhof in Haaren. Het festival wordt traditioneel gezien als de aftrap van het Nederlandse buitenfestivalseizoen, met een editie die telkens begin april plaatsvindt. REBiRTH onderscheidt zich door de opzet in meerdere themagebieden die zijn toegespitst op specifieke subgenres binnen hardstyle, rawstyle, hardcore en uptempo, waardoor het publiek per stijl een andere podiumervaring krijgt. Een terugkerend concept zijn de zogeheten Evolution Specials, waarin artiesten een uitgebreide set spelen die hun muzikale ontwikkeling door de jaren heen laat horen, vaak aangevuld met exclusieve edits en samenwerkingen die nergens anders te horen zijn. Voor de editie van 2026, van 10 tot en met 12 april, breidde de organisatie het uptempo-gebied RESiST fors uit en voegde met RESET x REVENGE een compleet nieuw podium toe dat zich richt op de hardcore-liefhebber, met een programmering die loopt van vroege en millennium-hardcore tot de explosieve 180 bpm-sound van nu. Het affiche bevatte diverse artiestenbattles, waarbij bevriende of rivaliserende acts gezamenlijk of achter elkaar optraden, zoals B-Front tegenover Phuture Noize en Dual Damage tegenover The Saints. Die combinatie van schaalgrootte, subgenre-specifieke gebieden en steeds wisselende, op maat gemaakte liveconcepten maakt dat REBiRTH inmiddels wordt gezien als een vaste waarde in de Nederlandse hardstyle- en hardcorekalender, met een productiewaarde die qua ambitie wedijvert met de grotere namen in de sector.','{hardstyle}','Akimbo, Bmberjck, Cryex, Lekkerfaces, Pinotello, B-Front, Phuture Noize, Dual Damage, The Saints, D-Sturb, Mish','Haaren','Duinenhof','Noord-Brabant','2026-04-10','2026-04-12','https://www.rebirthfestival.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 145.00, 'EUR', 'https://www.rebirthfestival.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'rebirth-festival';

-- 3. HARDFEST
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('hardfest','HARDFEST','HARDFEST is het hardstyle- en hardcorefestival van Oost-Nederland en wordt gehouden op de campus van de Universiteit Twente in Enschede. Het eendaagse evenement geldt in de regio als een vaste aftrap van het buitenfestivalseizoen en trekt traditioneel meer dan 20.000 bezoekers uit binnen- en buitenland. Het affiche bestaat doorgaans uit ruim 55 acts verdeeld over vier podia, deels overdekt zodat het festival ook bij minder gunstig weer kan doorgaan. De sfeer op HARDFEST wordt vaak omschreven als rauwer en intiemer dan bij de allergrootste hardstylefestivals: het terrein is compacter, waardoor het gevoel ontstaat van een hechte community van fans die elkaar van eerdere edities kennen. De festivalslogan We are Fire to the Flame onderstreept die passie voor de harder styles die de kern van het evenement vormt. Voor de kaartverkoop hanteert de organisatie een gefaseerd prijsmodel met vroegboekkorting, wat kenmerkend is voor de meeste Nederlandse hardstyle-evenementen van deze omvang. Door de ligging in Twente vervult HARDFEST een aanvullende rol naast de grotere festivals in Noord-Brabant en Limburg: het brengt de harder styles dichter bij het publiek in het oosten van het land en fungeert voor veel bezoekers als laagdrempelige eerste kennismaking met het genre, voordat ze doorstromen naar de grotere namen verderop in het seizoen. De editie van 2026 vond plaats op zaterdag 18 april.','{hardstyle}','Enschede','Diekmansportpark','Overijssel','2026-04-18','2026-04-18','https://www.hardfest.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 43.00, 'EUR', 'https://www.hardfest.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'hardfest';

-- 4. Decibel Outdoor
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('decibel-outdoor','Decibel Outdoor','Decibel Outdoor is het zomerse buitenbroertje van het gerenommeerde indoor-evenement Decibel en vindt sinds enkele jaren plaats op de uitgestrekte terreinen van Beekse Bergen in Hilvarenbeek. Het driedaagse festival, eind augustus, geldt als een van de afsluiters van het Nederlandse hardstyleseizoen en biedt met meer dan 250 artiesten verspreid over meerdere grote podia een volledig overzicht van de harder styles: van hardstyle en raw tot hardcore en uptempo. De combinatie van de open, groene omgeving van het safaripark met de zware productie van grote LED-schermen, pyrotechniek en uitgebreide podiumbouw zorgt voor een contrast dat bezoekers vaak als verrassend en sfeervol omschrijven. Waar het indoor-Decibel in het najaar bekendstaat om zijn intieme, donkere hallensfeer, kiest Decibel Outdoor bewust voor een luchtiger, festivalachtig zomerkarakter met camping- en lakeside-opties voor bezoekers die het hele weekend willen blijven. De organisatie bouwt de line-up doorgaans op met een mix van gevestigde headliners en jongere namen uit de raw- en uptempo-scene, waardoor het festival zowel de trouwe kern van de harder-stylesfamilie als een jongere aanwas aanspreekt. Voor de editie van 28 tot en met 30 augustus 2026 waren zowel losse dagtickets als een weekendcombinatie beschikbaar, met daarnaast camping- en lakeside-arrangementen voor wie het festivalgevoel wil verlengen tot na middernacht.','{hardstyle}','Hilvarenbeek','Beekse Bergen','Noord-Brabant','2026-08-28','2026-08-30','https://www.decibel-outdoor.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 49.95, 'EUR', 'https://www.decibel-outdoor.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'decibel-outdoor';

-- 5. Supremacy
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('supremacy','Supremacy','Supremacy presenteert zich al jaren als een van de belangrijkste podia binnen de raw hardstyle en organiseert zijn hoofdevenement in de Brabanthallen in ''s-Hertogenbosch, een locatie die met een capaciteit van circa 15.000 bezoekers plaats biedt aan een van de zwaarste line-ups binnen het genre. Het festival profileert zich expliciet als podium voor de rauwere, hardere kant van hardstyle en trekt daarmee een publiek dat weinig opheeft met de meer melodische varianten van het genre. De editie van 2026 draagt het thema State of Distortion en vindt plaats op 26 september. Kenmerkend voor Supremacy is het ledenmodel: trouwe bezoekers kunnen zich aanmelden als member en krijgen daardoor eerder toegang tot de kaartverkoop dan het grote publiek, wat het community-gevoel rond het festival versterkt en er in de praktijk toe leidt dat de eerste verkooprondes vaak al binnen een dag uitverkocht zijn. Het festival ligt op loopafstand van station ''s-Hertogenbosch, wat het voor internationale bezoekers relatief eenvoudig bereikbaar maakt zonder dat een auto nodig is. Naast het reguliere toegangsbewijs biedt de organisatie een VIP-optie met een eigen ingang, een verhoogd podiumzicht, aparte toiletten en een eigen bar. Op het moment van schrijven was de volledige line-up voor 2026 nog niet volledig onthuld, al werd aangekondigd dat de affichewijzigingen ten opzichte van eerdere jaren opnieuw voor de nodige ophef binnen de scene zouden zorgen.','{hardstyle}','''s-Hertogenbosch','Brabanthallen','Noord-Brabant','2026-09-26','2026-09-26','https://www.supremacy-hardstyle.com','announced',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', null, 'EUR', 'https://www.supremacy-hardstyle.com', 'unknown', '2026-07-03T09:00:00Z'
from festivals where slug = 'supremacy';

-- 6. Dominator Festival
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('dominator','Dominator Festival','Dominator Festival is een van de grootste hardcore-evenementen ter wereld en wordt sinds jaar en dag georganiseerd door Q-dance in samenwerking met Art of Dance. Het tweedaagse festival vindt plaats op het terrein Steenovens in Eersel en trekt een internationaal publiek dat speciaal voor deze editie naar Nederland afreist. In tegenstelling tot festivals die meerdere genres combineren, richt Dominator zich vrijwel volledig op hardcore in al zijn subvarianten, van klassieke gabber-invloeden tot de moderne, extreem snelle uptempo-hardcore. Het festival staat bekend om zijn massieve podiumbouw met indrukwekkende decors die elk jaar een ander thematisch verhaal vertellen, gecombineerd met een productie van licht, vuur en beeld die tot de zwaarste van de hardcore-scene wordt gerekend. Omdat het festival alleen toegankelijk is met een weekendticket inclusief camping, ontstaat er op het terrein een hechte, meerdaagse festivalervaring waarbij de camping zelf onderdeel wordt van de beleving, met eigen entertainment en ontmoetingsplekken tussen de sets door. De editie van 2026 vond plaats op 17 en 18 juli en bevestigde opnieuw de status van Dominator als een van de belangrijkste jaarlijkse bijeenkomsten van de wereldwijde hardcore-gemeenschap. Bezoekers uit tientallen landen combineren het festivalbezoek vaak met een verblijf van een lang weekend in Brabant, wat Dominator ook buiten het festivalterrein een economische en culturele impact geeft in de regio Eersel.','{hardcore}','Eersel','Steenovens','Noord-Brabant','2026-07-17','2026-07-18','https://www.dominator-festival.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 160.00, 'EUR', 'https://www.dominator-festival.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'dominator';

-- 7. Masters of Hardcore
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('masters-of-hardcore','Masters of Hardcore','Masters of Hardcore is een van de langstlopende en meest gerespecteerde hardcore-evenementen van Nederland en wordt normaliter georganiseerd in de Brabanthallen in ''s-Hertogenbosch. Het concept dankt zijn naam aan de gedachte dat het festival de absolute top van het genre samenbrengt, verdeeld over meerdere thematisch ingerichte zalen die elk een ander tijdperk of subgenre van hardcore belichten. Voor de editie van 28 maart 2026, met als thema Tides of Tyranny, bracht de organisatie onder meer een eerbetoon aan de Italiaanse hardcoretraditie op de mainstage, met namen als Noise Suppressor, Tommyknocker en Unexist, aangevuld met grote namen als Angerfist, Nosferatu, Tha Playah, Paul Elstak, Mad Dog en Miss K8. Een apart onderdeel, gewijd aan extreme hardcore, bood ruimte aan liveacts, terwijl een derde zaal volledig was ingericht rond face-to-face sets van artiesten die decennia geleden furore maakten in de vroege hardcore-jaren, zoals Marc Acardipane en Bass-D. Nieuw voor deze editie was een gebied dat zich specifiek richtte op vroege uptempo, een niche binnen de niche die door de kernfans van het festival zeer wordt gewaardeerd. Die combinatie van historisch besef en actuele hardcore maakt Masters of Hardcore uniek binnen het festivallandschap: het is zowel een feest voor nieuwe generaties fans als een eerbetoon aan de wortels van het genre, met een programmering die zelden buiten de eigen scene wordt nagebootst.','{hardcore}','Angerfist, Nosferatu, Tha Playah, Paul Elstak, Mad Dog, Miss K8, Noise Suppressor, Tommyknocker, Unexist, Marc Acardipane, Bass-D','''s-Hertogenbosch','Brabanthallen','Noord-Brabant','2026-03-28','2026-03-28','https://www.mastersofhardcore.com','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 55.00, 'EUR', 'https://www.mastersofhardcore.com', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'masters-of-hardcore';

-- 8. Harmony of Hardcore
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('harmony-of-hardcore','Harmony of Hardcore','Harmony of Hardcore is uitgegroeid tot een internationaal begrip binnen de hardcorescene en vindt jaarlijks plaats op het festivalterrein in Erp, Noord-Brabant. In tegenstelling tot de meeste grote Nederlandse hard-dance-evenementen programmeert Harmony of Hardcore uitsluitend rond hardcore-subgenres, zonder hardstyle of uptempo op het affiche, wat het festival een scherp afgebakende identiteit geeft binnen een scene die anders vaak genres combineert. Met veertien verschillende gebieden en een capaciteit van naar verluidt 45.000 bezoekers behoort het tot de grotere eendaagse festivals van het genre. De editie van 23 mei 2026 droeg het thema The Awakening of the Ultimate Hardcore Feeling en bracht meer dan tweehonderd acts samen, verspreid over tien podia die uiteenlopen van de meer melodieuze mainstage-hardcore tot de hoge bpm''s van terror en industrial. Angerfist gold opnieuw als een van de vaste afsluiters van de mainstage, een reeks optredens die het festival inmiddels als traditie beschouwt, terwijl artiesten als Endymion, Mark with a K en The Outside Agency zorgden voor de bredere stilistische spreiding binnen het genre. Harmony of Hardcore deelt het festivalweekend in de praktijk met 7th Sunday Festival, dat de dag erna op dezelfde locatie plaatsvindt, waardoor bezoekers uit binnen- en buitenland regelmatig kiezen voor een combinatiebezoek aan beide festivals in een weekend.','{hardcore}','Angerfist, Endymion, Mark with a K, The Outside Agency, Miss K8','Erp','De Grote Aok','Noord-Brabant','2026-05-23','2026-05-23','https://www.harmonyofhardcore.com','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 68.00, 'EUR', 'https://www.harmonyofhardcore.com', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'harmony-of-hardcore';

-- 9. 7th Sunday Festival
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('seventh-sunday-festival','7th Sunday Festival','7th Sunday Festival vindt plaats op de zondag van hetzelfde Pinksterweekend waarin een dag eerder, op dezelfde locatie in Erp, Harmony of Hardcore wordt gehouden, en de twee festivals worden door veel bezoekers dan ook als tweeluik bezocht. Waar Harmony of Hardcore zich puur op hardcore richt, kiest 7th Sunday voor een bredere, meer diverse programmering waarin hardstyle, house en dance-classics samenkomen op een dag. Voor de editie van 24 mei 2026 bracht de mainstage internationale housenamen als Afrojack, Axwell, Nicky Romero en Oliver Heldens samen met een speciale editie van La Fuente presents La Familia, terwijl het hardstyle-gedeelte werd gedragen door artiesten als D-Block & S-te-Fan, Radical Redemption, Ran-D en Sound Rush. Nieuw voor 2026 was onder meer het houseconcept Losjes en een area gewijd aan klassiekers onder de naam Francois presents Legends, wat het festival een nostalgisch element gaf naast de actuele hits. Die genre-mix maakt 7th Sunday een toegankelijker alternatief voor bezoekers die niet uitsluitend fan zijn van hardcore of pure hardstyle, en verklaart mede waarom het festival, ondanks de eendaagse opzet, is uitgegroeid tot een van de drukst bezochte evenementen in de regio tijdens het Pinksterweekend. De combinatie van een herkenbare locatie, een breed genreaanbod en de link met het voorgaande festival maakt 7th Sunday een uniek onderdeel van de Brabantse festivalkalender.','{hardstyle,hardcore}','Afrojack, Axwell, Nicky Romero, Oliver Heldens, D-Block & S-te-Fan, Radical Redemption, Ran-D, Sound Rush','Erp','De Grote Aok','Noord-Brabant','2026-05-24','2026-05-24','https://www.7thsunday.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 65.00, 'EUR', 'https://www.7thsunday.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'seventh-sunday-festival';

-- 10. Vroeger Was Alles Beter
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('vroeger-was-alles-beter','Vroeger Was Alles Beter','Vroeger Was Alles Beter, in de scene doorgaans afgekort tot VWAB, is een eendaags festival op het terrein van Autotron in Rosmalen dat volledig is gebouwd rond nostalgie binnen de hardstyle. In plaats van de nieuwste releases centraal te stellen, draait het festival om klassiekers en tracks uit voorgaande decennia van het genre, gebracht door artiesten die vaak zelf een deel van die geschiedenis hebben geschreven. Die insteek spreekt een publiek aan dat de hardstyle al langer volgt en de herkenning van bekende nummers waardeert boven de constante jacht op de nieuwste releases die bij veel andere hardstylefestivals centraal staat. De editie van 2026, op 11 juli, droeg het thema The Classics Cup en bood meer dan zeventig artiesten verdeeld over vier indoor- en outdoorpodia op het Autotron-terrein. Het festival heeft in korte tijd een trouwe achterban opgebouwd en behoort inmiddels tot de evenementen die snel uitverkocht raken, wat de positie van VWAB als vaste waarde binnen de zomerse hardstylekalender onderstreept. Door de combinatie van een compact, overzichtelijk terrein met een sterk uitgesproken nostalgisch concept onderscheidt VWAB zich van de grotere, bredere hardstylefestivals: het is minder gericht op schaal en meer op een gedeeld gevoel van herkenning tussen artiest en publiek rond muziek die voor veel bezoekers een emotionele lading heeft gekregen.','{hardstyle,mixed}','Rosmalen','Autotron','Noord-Brabant','2026-07-11','2026-07-11','https://www.vroegerwasallesbeter.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 69.00, 'EUR', 'https://www.vroegerwasallesbeter.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'vroeger-was-alles-beter';

-- 11. Jera On Air
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('jera-on-air','Jera On Air','Jera On Air is uitgegroeid tot een van de grootste punk-, metal- en hardcore-evenementen van Nederland en vindt sinds decennia plaats in het Limburgse dorp Ysselsteyn, tussen Eindhoven en Venlo. Wat begon als een kleinschalig lokaal initiatief is inmiddels een driedaags festival met vijf podia dat internationale headliners weet te strikken en tegelijk de doe-het-zelf-mentaliteit van de oorspronkelijke punkscene heeft behouden. De editie van 2026, de tweeendertigste in de geschiedenis van het festival, vond plaats van 25 tot en met 27 juni en bracht een lineup samen met Architects, The Offspring, Papa Roach, A Day To Remember, All Time Low en Hatebreed als grote namen, aangevuld met acts als Ice Nine Kills, Rise Against, Pennywise, Converge, Trivium en Alexisonfire. Naast de grote namen in metalcore en pop-punk bood het festival ook ruimte aan meer uiteenlopende punk- en crossover-acts zoals Viagra Boys, Bob Vylan en Turbonegro, wat de breedte van de programmering onderstreept. Jera On Air combineert het festivalprogramma met een campingervaring die door bezoekers vaak wordt geroemd om de informele, sociale sfeer, met signeersessies, een biertuin en een foodcourt als vaste onderdelen naast de podia. Die combinatie van een sterk internationaal affiche met een kleinschalige dorpssetting maakt Jera On Air tot een van de meest onderscheidende festivals binnen het Nederlandse metal- en punklandschap.','{metal,punk,hardcore}','Architects, The Offspring, Papa Roach, A Day To Remember, All Time Low, Hatebreed, Ice Nine Kills, Rise Against, Pennywise, Converge, Trivium, Alexisonfire','Ysselsteyn','Evenemententerrein Ysselsteyn','Limburg','2026-06-25','2026-06-27','https://www.jeraonair.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 239.00, 'EUR', 'https://www.jeraonair.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'jera-on-air';

-- 12. Roadburn Festival
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('roadburn','Roadburn Festival','Roadburn Festival geldt internationaal als een van de meest toonaangevende festivals voor avontuurlijke, grensverleggende metal en aanverwante genres, en vindt sinds jaar en dag plaats in en rond poppodium 013 in Tilburg. Het festival onderscheidt zich bewust van reguliere metalfestivals door zich niet te beperken tot bekende, publieksvriendelijke namen, maar juist ruimte te bieden aan experimentele, avant-gardistische en genre-overschrijdende acts binnen doom, sludge, drone, black metal en aanpalende stijlen. Ongeveer driekwart van het publiek reist voor Roadburn speciaal naar Nederland af, wat het festival een uitgesproken internationaal karakter geeft, ondanks de relatief compacte omvang van zo''n vierduizend bezoekers per dag. De editie van 2026, van 16 tot en met 19 april, bracht een affiche samen met onder meer Boris, Cult Of Luna, Inter Arma, Krallice, Nothing, Oathbreaker en Primitive Man, naast tal van minder bekende maar door kenners zeer gewaardeerde acts. Het festival vindt niet op een enkele locatie plaats maar verspreid over meerdere podia in het 013-complex en de omliggende Spoorzone, wat zorgt voor een intieme clubsfeer in plaats van de grootschalige festivalopzet die bij veel andere metalevenementen gebruikelijk is. Die combinatie van artistieke curatie, kleinschaligheid en internationale reputatie maakt Roadburn tot een festival dat wordt beschouwd als smaakmaker voor de bredere heavy-scene, waarbij een optreden op Roadburn voor veel bands wordt gezien als een erkenning van artistieke relevantie.','{metal,punk}','Boris, Cult Of Luna, Inter Arma, Krallice, Nothing, Oathbreaker, Primitive Man','Tilburg','013','Noord-Brabant','2026-04-16','2026-04-19','https://www.roadburn.com','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 284.00, 'EUR', 'https://www.roadburn.com', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'roadburn';

-- 13. Into The Grave
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('into-the-grave','Into The Grave','Into The Grave is het grootste metalfestival van Noord-Nederland en heeft zich in ruim tien edities ontwikkeld tot een vaste waarde binnen de Nederlandse metalkalender, met een geschiedenis van optredens van internationale grootheden als Slayer, Behemoth en Alestorm. Het festival wordt normaliter gehouden in Leeuwarden, waarbij de historische Oldehoofsterkerkhof-locatie in het centrum van de stad een herkenbare, sfeervolle setting biedt die een combinatie vormt van cultureel erfgoed en zware metalmuziek. Voor de editie van 2026 keerde het festival terug naar deze vertrouwde locatie na een eerdere editie op een tijdelijke plek in het Leeuwarder Stationskwartier. Rondom het hoofdprogramma organiseert poppodium Neushoorn traditioneel pre- en afterparty''s, waardoor het festivalbezoek voor veel fans een meerdaagse aangelegenheid wordt binnen de stad. Kort voor de editie van 2026 verkocht de langjarige organisator zijn aandeel in het festival, wat binnen de scene met belangstelling werd gevolgd, al bleef de koers van het festival grotendeels ongewijzigd. De aangekondigde line-up voor 2026 bevat met Anthrax, Mastodon en Lacuna Coil drie namen die elk een ander deel van het bredere metalspectrum vertegenwoordigen, van klassieke thrash tot progressieve en gothic metal, wat past bij de brede programmering die Into The Grave als festival nastreeft. Door de combinatie van een unieke locatie, een sterke reputatie in het noorden van het land en een breed opgezet affiche blijft Into The Grave een van de belangrijkste metalevenementen buiten de Randstad.','{metal}','Anthrax, Mastodon, Lacuna Coil','Leeuwarden','Neushoorn','Friesland','2026-11-14','2026-11-14','https://www.intothegrave.nl','announced',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', null, 'EUR', 'https://www.intothegrave.nl', 'unknown', '2026-07-03T09:00:00Z'
from festivals where slug = 'into-the-grave';

-- 14. WOO HAH!
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('woo-hah','WOO HAH!','WOO HAH! is een naam met een lange geschiedenis binnen de Nederlandse hiphopfestivalscene: het evenement ontstond in Tilburg en groeide in de jaren daarna uit tot een van de bekendere hiphop- en urban-festivals van het land, met een verhuizing naar Safaripark Beekse Bergen in latere edities. Rond de merknaam is de afgelopen jaren het nodige veranderd, met samenwerkingen en naamswijzigingen binnen de organisatie die de precieze status en invulling van latere edities minder eenduidig maken dan bij festivals met een stabielere geschiedenis. Voor deze beschrijving geldt daarom een terughoudende inschatting: WOO HAH! staat historisch bekend als een festival dat Nederlandse en internationale hiphop, R&B en aanverwante urban-genres combineert, met een programmering die zowel gevestigde artiesten als opkomend talent een podium biedt. Kenmerkend voor het festivalconcept is de laagdrempelige, feestelijke sfeer die aansluit bij een jong, divers publiek, met naast de muziek ook aandacht voor foodtrucks, streetart en andere onderdelen van de urban-cultuur. Concrete, bevestigde artiestennamen voor de editie van 2026 waren op het moment van schrijven niet met zekerheid vast te stellen, wat past bij een festival waarvan de precieze doorontwikkeling van editie tot editie kan verschillen. Bezoekers die specifiek geinteresseerd zijn in de actuele line-up en locatie doen er daarom goed aan de officiele kanalen van het festival in de aanloop naar de zomer van 2026 in de gaten te houden.','{hiphop,urban}','Tilburg','Spoorpark','Noord-Brabant','2026-08-14','2026-08-15','https://woohahfestival.com','tickets_live',false);

