from festivals where slug = 'woo-hah';

-- 15. UrbanMatterz
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('urbanmatterz','UrbanMatterz','UrbanMatterz is een jaarlijks urban- en hiphopfestival in Helmond dat zich niet beperkt tot alleen muziek, maar nadrukkelijk is opgebouwd rond vier pijlers: muziek, urban sports, cultuur en educatie. Naast concerten en dj-sets omvat het programma daarom ook disciplines als dans, dj''en, mc''en en graffiti, waarmee het festival zich presenteert als een breder cultureel platform voor de urban-scene dan een traditioneel muziekfestival. De editie van 2026 markeert de tiende en volgens de organisatie ook de laatste editie van UrbanMatterz, wat er de komende jaren een bijzondere, afsluitende betekenis aan geeft binnen de Brabantse festivalkalender. Onderdeel van dit jubileumjaar is een Oldskool HipHop Concert op 5 september 2026, dat in tegenstelling tot voorgaande jaren niet in Helmond maar bij Effenaar in Eindhoven plaatsvindt als onderdeel van wat de organisatie het Final Chapter noemt. Voor dit concert zijn met DEAMS, Stetsasonic, Mantronix, Just-Ice, Grand Wizzard Theodore, Schoolly D en Tuff Crew namen bevestigd die stuk voor stuk tot de grondleggers en pioniers van de old-schoolhiphop worden gerekend, wat het concert een uitgesproken historisch karakter geeft binnen het bredere UrbanMatterz-programma. Door de combinatie van een langlopende regionale traditie, een brede culturele insteek en een afscheidseditie met erkende hiphoppioniers krijgt UrbanMatterz in 2026 een andere, meer symbolische lading dan in voorgaande jaren.','{hiphop,urban}','DEAMS, Stetsasonic, Mantronix, Just-Ice, Grand Wizzard Theodore, Schoolly D, Tuff Crew','Helmond','Centrum Helmond','Noord-Brabant','2026-09-05','2026-09-05','https://urbanmatterz.nl','announced',false);

