select id, 'official', null, 'EUR', 'https://urbanmatterz.nl', 'unknown', '2026-07-03T09:00:00Z'
from festivals where slug = 'urbanmatterz';

-- 16. Appelsap Festival
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('appelsap','Appelsap Festival','Appelsap Festival is uitgegroeid van een gratis zomerjam in het jaar 2000 tot een van de belangrijkste hiphopfestivals van Amsterdam, met een programmering die hiphop, grime, r&b en aanverwante urban- en electronic-invloeden samenbrengt. Het festival heeft in de loop der jaren een reputatie opgebouwd als proeftuin voor Nederlands talent naast internationale namen, waardoor het voor veel opkomende artiesten uit de Nederlandse hiphopscene een belangrijk podium is geworden om zich aan een breder publiek te presenteren. De editie van 2026 vindt plaats op 1 en 2 augustus in het Diemerpark, een locatie die het festival in latere jaren heeft betrokken nadat eerdere edities plaatsvonden op het Flevopark. Kenmerkend voor Appelsap is de laagdrempelige, buurtgerichte sfeer: ondanks de groei van het festival in bezoekersaantallen en naamsbekendheid blijft de nadruk liggen op toegankelijkheid, mede zichtbaar in het feit dat kinderen tot twaalf jaar gratis toegang krijgen. Tickets worden in opeenvolgende verkooprondes tegen oplopende prijzen aangeboden, wat vroege kopers beloont en tegelijk bijdraagt aan de organische groei van de belangstelling richting de festivaldatum. Door de combinatie van een sterke lokale verankering in Amsterdam-Oost, een uitgesproken focus op hiphop en aanverwante genres, en een geschiedenis die teruggaat tot een informeel buurtinitiatief, onderscheidt Appelsap zich van de grotere, meer commerciele urban-festivals in Nederland.','{hiphop,urban}','Amsterdam','Diemerpark','Noord-Holland','2026-08-01','2026-08-02','https://www.appelsap.net','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
