from festivals where slug = 'appelsap';

-- 17. Vunzige Deuntjes Festival
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('vunzige-deuntjes','Vunzige Deuntjes Festival','Vunzige Deuntjes Festival is uitgegroeid tot een van de drukst bezochte urban- en dance-crossoverfestivals in de regio Amsterdam en vindt jaarlijks plaats in het Amsterdamse Bos, op de grens van Amsterdam en Amstelveen. Het festival combineert urban-genres als hiphop met house en aanverwante dancemuziek over meerdere podia, wat zorgt voor een genre-mix die een breder publiek aanspreekt dan festivals die zich puur op een stijl richten. Met meer dan twintigduizend bezoekers verspreid over ruim zes podia biedt het festival naast de muzikale line-up ook een uitgebreid randprogramma, met een cultuurmarkt, dansbattles, een area gewijd aan een eigen spelconcept en een auto-tune-karaoke-onderdeel dat inmiddels een van de bekendere attracties van het festival is geworden. De bosrijke setting van het Amsterdamse Bos geeft het festival een informelere, meer ontspannen sfeer dan de meeste stedelijke urban-evenementen, met ruimte voor bezoekers om tussen de podia door ook gewoon in het groen te verblijven. De editie van 2026 vindt plaats op zaterdag 4 juli en trekt traditiegetrouw ruim voor de festivaldatum al veel belangstelling, wat maakt dat tickets doorgaans geruime tijd voor de festivaldag uitverkocht raken. Die combinatie van een sterke lokale aanhang, een brede genreprogrammering en een onderscheidende locatie in het groen maakt Vunzige Deuntjes tot een van de eigenzinnigere urban-festivals van Nederland.','{urban,house,hiphop}','Amstelveen','Amsterdamse Bos','Noord-Holland','2026-07-04','2026-07-04','https://www.vunzigedeuntjes.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 69.89, 'EUR', 'https://www.vunzigedeuntjes.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'vunzige-deuntjes';

-- 18. Zomercarnaval Rotterdam
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('zomercarnaval','Zomercarnaval Rotterdam','Zomercarnaval, onderdeel van het bredere Rotterdam Unlimited-programma, is een van de grootste caribische en tropische carnavalsevenementen van Europa en trekt jaarlijks honderdduizenden bezoekers naar het centrum van Rotterdam. Het hart van het festival wordt gevormd door de straatparade over de Coolsingel, waarin ongeveer tweeduizend deelnemers uit verschillende caribische en Surinaamse carnavalstradities meedoen met kleurrijke kostuums, praalwagens en muziek. Sinds 2023 is het Zomercarnaval, en in het bijzonder de straatparade, door UNESCO erkend als immaterieel cultureel erfgoed, wat de culturele waarde van het evenement voor de Surinaamse en Caribische gemeenschap in Nederland onderstreept. Naast de parade zelf bestaat het programma uit onderdelen als de Battle of Drums, waarin percussiegroepen het tegen elkaar opnemen, en Mercado, een culinair festivalonderdeel met gerechten uit Suriname, het Caribisch gebied en daarbuiten, verspreid langs de Coolsingel. Het grootste deel van het programma, waaronder de straatparade zelf, is gratis toegankelijk voor publiek, wat het Zomercarnaval tot een van de meest laagdrempelige grootschalige evenementen van Nederland maakt. Voor bezoekers die de parade in meer comfort willen beleven, biedt de organisatie een beperkt aantal VIP-plaatsen op een tribune aan de Coolsingel, inclusief eten en drinken, als betaald alternatief naast de gratis toegankelijke straat. De editie van 2026 vindt plaats op 24 en 25 juli, met de straatparade op de zaterdag als traditioneel hoogtepunt van het weekend.','{urban,mixed}','Rotterdam','Coolsingel','Zuid-Holland','2026-07-24','2026-07-25','https://www.zomercarnaval.org','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 24.50, 'EUR', 'https://www.zomercarnaval.org', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'zomercarnaval';

-- 19. Milkshake Festival
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('milkshake-festival','Milkshake Festival','Milkshake Festival begon in 2012 als een klein initiatief in het centrum van Amsterdam en is uitgegroeid tot een van de bekendste inclusieve dance- en cultuurfestivals van Europa, met een uitgesproken focus op diversiteit, gender-expressie en lhbtiq+-cultuur naast een breed elektronisch muziekprogramma. Het festival vindt jaarlijks plaats in het Amsterdamse Westerpark en combineert house, techno en aanverwante genres met performance art, dragshows en een uitgesproken visuele, kleurrijke esthetiek die het festival onderscheidt van reguliere dancefestivals. Met traditioneel meer dan tien podia per dag biedt Milkshake ruimte aan zowel internationale dance-acts als artiesten die primair bekend zijn binnen de queer- en performancecultuur. Voor de editie van 25 en 26 juli 2026 bracht de organisatie een affiche samen van meer dan 160 artiesten, met namen als Underground Resistance, de combinatie RHR & Skrillex, CCL en Helena Hauff & L.F.T. op het elektronische deel van het programma, aangevuld met performers als Bob the Drag Queen en Pabllo Vittar die de bredere culturele component van het festival vertegenwoordigen. Die combinatie van zware dance-programmering en een uitgesproken maatschappelijke, inclusieve boodschap maakt Milkshake tot meer dan een muziekfestival alleen: het evenement wordt binnen en buiten Nederland gezien als een belangrijk podium voor zichtbaarheid van lhbtiq+-cultuur, terwijl het tegelijkertijd een van de kwalitatief hoogst aangeschreven dance-line-ups van de Nederlandse zomer biedt.','{house,urban,mixed}','Underground Resistance, RHR & Skrillex, CCL, Helena Hauff & L.F.T., Bob the Drag Queen, Pabllo Vittar','Amsterdam','Westerpark','Noord-Holland','2026-07-25','2026-07-26','https://www.milkshakefestival.com','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 47.50, 'EUR', 'https://www.milkshakefestival.com', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'milkshake-festival';

-- 20. North Sea Jazz Festival
insert into festivals (slug, name, description, genres, lineup, city, venue, province, start_date, end_date, website_url, status, published) values
('north-sea-jazz','North Sea Jazz Festival','North Sea Jazz Festival is al vijftig jaar een vaste waarde in de internationale jazzwereld en geldt als een van de grootste indoor-jazzfestivals ter wereld. Het festival vindt plaats in Rotterdam Ahoy, waar op meer dan een stuk of vijftien podia tegelijkertijd optredens plaatsvinden, verspreid over verschillende zalen binnen het complex. Ondanks de naam beperkt het programma zich al decennia niet tot pure jazz: soul, r&b, funk, hiphop en pop maken vast onderdeel uit van de line-up, wat het festival een breder bereik geeft dan een puristisch jazzevenement. De editie van 2026, van 10 tot en met 12 juli, markeert de vijftigste verjaardag van het festival en bracht een uitzonderlijk sterk affiche samen met onder anderen Diana Krall, Esperanza Spalding, Jon Batiste en The Isley Brothers op vrijdag, Charlie Puth, Joy Crookes, Incognito, Cassandra Wilson en Selah Sue op zaterdag, en Adrian Younge, Charles Lloyd Quartet, John Legend, Nile Rodgers & CHIC en Pat Metheny Side Eye III op zondag. Die combinatie van gevestigde jazzgrootheden, hedendaagse soul- en r&b-sterren en mainstream pop-acts maakt North Sea Jazz tot een festival dat verschillende generaties en muzieksmaken bij elkaar brengt binnen een weekend. Het jubileumkarakter van de vijftigste editie zorgde voor extra belangstelling vanuit binnen- en buitenland, wat zich vertaalde in een vroege uitverkoop van meerdaagse tickets ruim voor de festivaldatum.','{jazz}','Diana Krall, Esperanza Spalding, Jon Batiste, The Isley Brothers, Charlie Puth, Joy Crookes, Incognito, Cassandra Wilson, Selah Sue, John Legend, Nile Rodgers & CHIC, Pat Metheny Side Eye III','Rotterdam','Ahoy','Zuid-Holland','2026-07-10','2026-07-12','https://www.northseajazz.com','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 145.00, 'EUR', 'https://www.northseajazz.com', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'north-sea-jazz';

-- 21. Le Guess Who?
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('le-guess-who','Le Guess Who?','Le Guess Who? is een van de meest eigenzinnige muziekfestivals van Nederland en presenteert zich nadrukkelijk niet als een festival met een vaste headliner-mainstage-formule, maar als een ontdekkingsreis door avontuurlijke, grensverleggende muziek uit de hele wereld. Het festival vindt sinds de oprichting plaats in Utrecht, met TivoliVredenburg als hoofdlocatie, aangevuld met meer dan dertig andere locaties door de hele stad, van eeuwenoude kerken tot industriele pakhuizen en verborgen kelders langs de grachten. Die spreiding over de stad geeft Le Guess Who? een uniek karakter binnen het festivallandschap: bezoekers verplaatsen zich tussen optredens door letterlijk door het centrum van Utrecht, wat het festival meer laat aanvoelen als een stadsbrede muzikale ontdekkingstocht dan als een afgebakend festivalterrein. Een terugkerend element is de rol van gastcuratoren, die samen met de organisatie delen van het programma samenstellen en zo hun eigen muzikale netwerk en smaak inbrengen in het affiche, van wereldmuziek en folk tot avant-gardistische jazz en underground elektronische muziek. De editie van 2026, van 5 tot en met 8 november, markeert de twintigste editie van het festival en werd om die reden aangekondigd als een bijzondere jubileumeditie. Bezoekers kunnen kiezen tussen een volledig vierdaags passe-partout of losse dagtickets, afhankelijk van hoeveel van het brede en uiteenlopende programma zij willen meemaken. Op het moment van schrijven was de volledige artiestenline-up voor deze editie nog niet definitief bekendgemaakt.','{folk,jazz,mixed}','Utrecht','TivoliVredenburg','Utrecht','2026-11-05','2026-11-08','https://www.leguesswho.com','announced',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
