from festivals where slug = 'le-guess-who';

-- 22. Reggae Roots
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('reggae-roots','Reggae Roots','Reggae Roots is een reggaegericht festival dat zich richt op de bredere Caribische en Surinaamse muziekgemeenschap in Nederland, met een programma dat zich naar verluidt concentreert op roots reggae, dancehall en aanverwante geluiden binnen de bredere urban- en wereldmuziekscene. Concrete, geverifieerde informatie over de exacte invulling van de editie van 2026 was op het moment van schrijven beperkt beschikbaar, wat bij kleinere en regionale festivals als dit vaker voorkomt dan bij de grote landelijke namen. Wel is duidelijk dat reggae in Nederland al decennialang een eigen, trouwe aanhang kent, met een netwerk van kleinere en middelgrote festivals die doorgaans in de zomer plaatsvinden en een combinatie bieden van live bands, dj-sets, Caribische foodstalls en een ontspannen, buitenfestivalsfeer die sterk verschilt van de grotere, commerciele dancefestivals. De editie van 4 juli 2026 sluit qua opzet aan bij dat bredere beeld: een eendaags festival met een programma dat naar verwachting zowel gevestigde als opkomende reggae- en dancehallartiesten combineert. Voor bezoekers die specifiek geinteresseerd zijn in de exacte line-up, podiumindeling en actuele status van het evenement is het gezien de beperkte publiek beschikbare informatie aan te raden de officiele kanalen van het festival in de aanloop naar de zomer te blijven volgen, aangezien details rond dit soort kleinere regionale reggae-evenementen relatief laat definitief worden.','{urban,mixed}','Den Haag','Zuiderpark','Zuid-Holland','2026-07-04','2026-07-04','https://www.reggaeroots.nl','tickets_live',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 37.50, 'EUR', 'https://www.reggaeroots.nl', 'available', '2026-07-03T09:00:00Z'
from festivals where slug = 'reggae-roots';

-- 23. Supersized Kingsday
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('supersized-kingsday','Supersized Kingsday','Supersized Kingsday Festival is uitgegroeid tot het grootste Koningsdagfestival van Nederland en vindt jaarlijks plaats op het Aquabest-terrein in Best, vlakbij Eindhoven. Met naar schatting zo''n vijftigduizend bezoekers combineert het festival de nationale feestdag met een dagvullend programma binnen hardstyle, raw en uptempo, wat het tot een van de drukst bezochte eendaagse hardstyle-evenementen van het land maakt. Kenmerkend voor Supersized is de koppeling aan Koningsdag als thema: de organisatie brengt ieder jaar exclusieve Supersized-specials waarin bekende artiesten een unieke show brengen die is toegespitst op de feestelijke, nationale sfeer van de dag, aangevuld met extra veel confetti- en pyro-effecten passend bij het uitbundige karakter van de datum. Voor de editie van 27 april 2026 investeerde de organisatie in een compleet nieuw mainstage-ontwerp, wat aansluit bij de ambitie van het festival om qua productiewaarde mee te blijven groeien met de grotere namen binnen de hardstylescene. Doordat het festival samenvalt met een nationale feestdag trekt Supersized een breed publiek, van vaste hardstylefans tot bezoekers die Koningsdag vooral als aanleiding zien voor een dagje uit met vrienden. Die combinatie van een herkenbare feestdag, een groeiende productie en een centrale ligging nabij Eindhoven maakt Supersized Kingsday tot een van de vaste onderdelen van de Nederlandse festivalkalender rond eind april.','{hardstyle}','Best','Recreatieplas Aquabest','Noord-Brabant','2026-04-27','2026-04-27','https://www.supersizedfestival.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 59.95, 'EUR', 'https://www.supersizedfestival.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'supersized-kingsday';

-- 24. Mystic Winter Garden
insert into festivals (slug, name, description, genres, city, venue, province, start_date, end_date, website_url, status, published) values
('mystic-winter-garden','Mystic Winter Garden','Mystic Winter Garden is de winterse indoor-uitvoering van het bekendere zomerfestival Mystic Garden Festival en vindt plaats in de hallen van Autotron in Rosmalen, waar verwarmde tenten en een sprookjesachtige aankleding zorgen voor een sfeer die sterk afwijkt van de kille buitenlucht van eind maart. Het festival profileert zich nadrukkelijk als een magische, sprookjesachtige beleving binnen de elektronische muziek, met een aankleding die verder gaat dan de gebruikelijke festivaldecoraties en een duidelijk eigen visuele identiteit nastreeft. Het programma wordt verdeeld over meerdere podia die elk worden gecureerd door een ander concept of samenwerkende partij, waaronder Mystic Garden Festival zelf, Dockyard Festival, Cirque Mystique en TIJDMASJIEN, wat zorgt voor uiteenlopende muzikale invalshoeken binnen het bredere elektronische spectrum, van housetinten tot meer experimentele of circusachtige podiumconcepten. Duurzaamheid en inclusiviteit worden door de organisatie expliciet genoemd als kernwaarden van het festival, wat zich onder meer vertaalt in de manier waarop het evenement wordt ingericht en gecommuniceerd. Doordat het festival volledig indoor plaatsvindt, is Mystic Winter Garden minder afhankelijk van het weer dan de zomerse festivals van dezelfde makers, wat het tot een aantrekkelijke optie maakt voor bezoekers die vroeg in het jaar al naar een festivalervaring verlangen. De editie van 21 maart 2026 bevestigde de positie van het festival als vaste winterse aanvulling op de bredere Mystic-portfolio van dance-evenementen.','{electronic,mixed}','Rosmalen','Autotron','Noord-Brabant','2026-03-21','2026-03-21','https://www.mysticgardenfestival.nl','past',false);

insert into ticket_offers (festival_id, provider, price_from, currency, url, availability, last_checked_at)
select id, 'official', 55.00, 'EUR', 'https://www.mysticgardenfestival.nl', 'sold_out', '2026-07-03T09:00:00Z'
from festivals where slug = 'mystic-winter-garden';

-- === Extra gidsartikelen (5) ===
insert into articles (slug, title, excerpt, content, seo_title, seo_description, published_at) values
('goedkope-festivaltickets-scoren','Goedkope festivaltickets scoren: bewezen tactieken','Met de juiste timing en het juiste platform bespaar je flink op festivaltickets, als je de valkuilen maar kent.',e'## Vroeg boeken loont (meestal)\n\nDe meeste festivals hanteren een prijsstructuur die oploopt naarmate de startdatum dichterbij komt: early bird, dan reguliere prijs, dan last-minute prijs. Wie in de eerste verkoopronde toeslaat, betaalt vaak 20 tot 40 euro minder dan wie pas in het voorjaar boekt. Nadeel: je weet nog niet wie er optreedt en je zit vast aan een aankoop die je niet zomaar terugkrijgt.\n\n**Tip:** volg de socials van het festival vanaf november. Early bird-tickets zijn vaak binnen een paar dagen uitverkocht.\n\n## Wachten tot vlak voor het festival\n\nTegenovergesteld aan vroegboeken is de gok op een prijsdaling vlak voor het festival op doorverkoopplatforms. Verkopers die om wat voor reden dan ook niet meer kunnen, willen hun geld liever gedeeltelijk terug dan helemaal niet. In de laatste week voor een festival zie je op TicketSwap en Gigsberg regelmatig tickets onder de oorspronkelijke prijs opduiken.\n\nDit is wel een risicovollere tactiek: bij populaire festivals die uitverkocht zijn, blijft de vraag hoog en dalen prijzen nauwelijks. Bij festivals met een minder sterke line-up of concurrerend aanbod in hetzelfde weekend zie je vaker een duidelijke daling.\n\n## Vergelijk tussen platforms\n\nDe officiële website, TicketSwap, Gigsberg en soms Ticketmaster kunnen voor hetzelfde festival andere prijzen tonen. Het loont om voor je koopt even te shoppen: FestivalDiscounter zet die opties naast elkaar zodat je niet zelf vijf tabbladen open hoeft te houden. Let wel op bijkomende kosten zoals servicekosten en verzendkosten, die per platform flink kunnen verschillen en het prijsvoordeel soms tenietdoen.\n\n## Waar je juist niet op moet trappen\n\n- **Te mooi om waar te zijn.** Een uitverkocht festival waarvoor plotseling tientallen tickets ver onder de prijs opduiken op Instagram of Marktplaats, is verdacht.\n- **Betalen buiten een platform om.** Zodra je betaalt via een linkje of Tikkie aan een onbekende buiten TicketSwap of Gigsberg om, heb je geen enkele bescherming als het ticket niet blijkt te bestaan.\n- **Screenshots van tickets.** Een foto van een ticket zegt niets over eigendom; het originele ticket kan nog gewoon gebruikt worden door de verkoper zelf.\n- **Kunstmatige druk ("nu kopen, nog maar 1 over").** Een klassieke verkooptruc, ook bij legitieme doorverkoop. Neem de tijd om de verkoper en het aanbod te checken.\n\nKoop bij twijfel altijd via een platform met kopersbescherming, ook als het net iets duurder is. Het verschil tussen een paar euro besparen en een niet-bestaand ticket is precies het bedrag dat je kwijt bent.','Goedkope festivaltickets scoren: bewezen tactieken','Bespaar op festivaltickets met vroegboekvoordeel, slim vergelijken tussen platforms en tijdig instappen op doorverkoop. Plus: herken nepaanbiedingen.','2026-07-03T10:00:00Z'),
('festival-inpaklijst','Festival-inpaklijst: dit neem je mee (en dit laat je thuis)','Een complete inpaklijst voor je festivalcamping, met extra aandacht voor Nederlands weer en de spullen die iedereen vergeet.',e'## De basis: wat je altijd nodig hebt\n\n- Tent (getest en compleet, inclusief alle haringen en stormkoord)\n- Slaapzak en een goede slaapmat of luchtbed: de grond is kouder dan je denkt, ook in juli\n- Oordopjes, ook als je niet naast een podium slaapt\n- Powerbank plus kabel, want stopcontacten zijn schaars op de camping\n- Contant geld voor kluisjes en cash-only kraampjes\n- Identiteitsbewijs en polsbandje of ticket goed opgeborgen\n\n## Nederlands weer: reken op regen\n\nEen festivalweekend zonder regenbui is eerder uitzondering dan regel. Pak in elk geval mee:\n\n- **Een poncho of regenjas** die ook nog werkt als het hard waait\n- **Waterdichte schoenen** naast je festivalschoenen: modder droogt niet op tijd\n- **Grondzeil of extra plastic** onder de tent, standaard tentbodems houden bij aanhoudende regen niet alles tegen\n- **Een vuilniszak** voor natte kleding op de terugweg\n\nBij hitte is de tent juist een oven vanaf een uur of tien. Denk aan een zonnescherm of extra doek over de tent, genoeg water en zonnebrandcreme, ook op een bewolkte dag.\n\nWissel het weer af binnen een weekend, dan is een tent die zowel schaduw als bescherming tegen wind biedt goud waard. Kies bij twijfel liever een iets duurdere, stevigere tent dan de goedkoopste variant uit de supermarkt: die overleeft zelden een hele nacht stevige wind.\n\n## Wat vaak vergeten wordt\n\n- **Oplaadkabel-verdeelstekker of splitter.** Als er wel stroom is, wil iedereen er tegelijk bij.\n- **Pleisters en blaarplak.** Na een dag lopen op festivalterrein zijn blaren de meest voorkomende klacht bij de EHBO-post.\n- **Oordopjes voor overnachten**, niet alleen voor bij het podium.\n- **Reserve batterijen of een tweede powerbank**: één keer opladen is vaak niet genoeg voor drie dagen.\n- **Een kleine hoofdlamp.** Zoeken naar spullen in een donkere tent met je telefoon als lamp is de snelste manier om je batterij leeg te trekken.\n- **Wc-papier en handgel.** Voorraden bij de camping-toiletten raken op piekmomenten op.\n\n## Wat je beter thuis laat\n\n- Waardevolle sieraden en dure elektronica die je niet per se nodig hebt\n- Glas: op vrijwel elk festivalterrein en camping verboden\n- Te veel bagage: een grote koffer op wielen is onhandig op gras en modder, een rugzak of trolleytas werkt beter\n- Je enige mooie schoenen: die zijn na dag een toch niet meer wit\n\n## Kort samengevat\n\nPak voor comfort (slapen, droog blijven, opladen), niet voor de show. Spullen voor onderweg naar het podium neem je mee in een klein tasje, de rest blijft op de camping. Een paar euro extra aan regenkleding en een tweede powerbank voorkomt het meeste festivalleed.','Festival-inpaklijst: wat neem je mee op camping?','Complete festival-inpaklijst voor de camping: van regenkleding tot powerbank en vaak vergeten spullen. Ontdek wat je meeneemt en wat je beter thuislaat.','2026-07-03T14:00:00Z'),
('hoe-werkt-gigsberg','Hoe werkt Gigsberg? Ticketmarktplaats uitgelegd','Gigsberg is naast TicketSwap een populaire ticketmarktplaats: dit is hoe het werkt en hoe je er veilig op koopt.',e'## Wat is Gigsberg?\n\nGigsberg is een online marktplaats voor het kopen en verkopen van tickets voor concerten, festivals en sportevenementen. Net als TicketSwap treedt Gigsberg op als tussenpersoon tussen particuliere verkopers en kopers, en neemt het platform verificatie en betaling voor zijn rekening zodat je niet rechtstreeks met een onbekende hoeft te handelen.\n\n## Hoe koop je veilig via Gigsberg?\n\n- **Betaal altijd via het platform zelf**, nooit rechtstreeks aan de verkoper via een bankoverschrijving of Tikkie buiten Gigsberg om.\n- **Let op het type ticket.** Sommige tickets worden na aankoop automatisch op jouw naam gezet (vergelijkbaar met SecureSwap bij TicketSwap), andere zijn een pdf of barcode die je rechtstreeks van de verkoper ontvangt. Bij het laatste is er een iets groter risico dat een ticket dubbel wordt verkocht.\n- **Check de beoordeling van de verkoper**, als die beschikbaar is.\n- **Bewaar alle communicatie binnen het platform**, zodat je bij een geschil bewijs hebt.\n- **Vergelijk de prijs met de originele ticketprijs.** Ook Gigsberg hanteert regels tegen woekerprijzen, maar het loont om te checken wat een ticket origineel kostte voor je akkoord gaat.\n\n## Verschillen met TicketSwap\n\n- **Bereik:** TicketSwap is in Nederland het grootste en bekendste platform, met het grootste aanbod voor Nederlandse festivals. Gigsberg is internationaler georienteerd en richt zich sterk op concerten en sportwedstrijden naast festivals.\n- **Prijsplafond:** TicketSwap hanteert een harde grens van 120 procent van de oorspronkelijke prijs. Bij Gigsberg kan dit per evenement verschillen, dus check dit altijd voordat je koopt of verkoopt.\n- **Ticketoverdracht:** TicketSwap werkt bij veel grote Nederlandse festivals samen met de organisatie voor automatische naamswijziging (SecureSwap). Gigsberg biedt dit bij een deel van de aangesloten evenementen, maar niet overal, dus controleer dit per festival.\n- **Aanbod per festival:** Voor Nederlandse festivals heeft TicketSwap doorgaans het grootste aanbod, maar bij uitverkochte evenementen loont het om beide platforms te vergelijken; aanbod en prijs kunnen flink verschillen.\n\n## Wanneer kies je voor Gigsberg?\n\nVooral handig als een festival of concert niet of nauwelijks op TicketSwap te vinden is, of als je merkt dat het aanbod daar te duur is. Vergelijk voor je koopt sowieso beide platforms: via FestivalDiscounter zie je in een overzicht welke ticketmarktplaatsen een aanbieding hebben voor het festival dat je zoekt.\n\n## Kort samengevat\n\nGigsberg werkt in de kern hetzelfde als andere doorverkoopplatforms: veilig kopen betekent altijd binnen het platform blijven, verifieren wat voor type ticket je koopt en niet toehappen op een deal die buiten het systeem om loopt.','Hoe werkt Gigsberg? Ticketmarktplaats uitgelegd','Wat is Gigsberg precies, hoe koop je er veilig een festivalticket en wat is het belangrijkste verschil met TicketSwap? Alle antwoorden en tips op een rij.','2026-07-04T09:00:00Z'),
('uitverkocht-festival-toch-nog-in','Uitverkocht festival: zo kom je er toch nog in','Een festival is uitverkocht, maar dat betekent niet dat je er niet meer bij kunt komen: dit zijn de legale routes.',e'## Check doorverkoopplatforms eerst\n\nZodra een festival uitverkocht is, verschuift het aanbod naar platforms als TicketSwap en Gigsberg. Mensen die door ziekte, een dubbele boeking of gewijzigde planning niet kunnen, verkopen hun ticket door. Bij grote Nederlandse festivals komen er in de weken voor het evenement doorgaans dagelijks nieuwe tickets bij.\n\n**Tip:** stel, als het platform dat toelaat, een melding in voor het festival zodat je een seintje krijgt zodra er een ticket beschikbaar komt, in plaats van continu te moeten verversen.\n\n## Wachtlijsten bij de organisatie\n\nSteeds meer festivals werken met een officiele wachtlijst op hun eigen website. Als er tickets terugkomen, bijvoorbeeld doordat een koper zich terugtrekt binnen de bedenktijd, worden die eerst aangeboden aan mensen op de wachtlijst, vaak tegen de originele prijs en zonder de extra kosten van een doorverkoopplatform. Dit is de veiligste en vaak goedkoopste route, dus check dit altijd als eerste optie.\n\n## Dagtickets komen later vaak nog vrij\n\nBij meerdaagse festivals wordt de verkoop soms per dag apart geopend, en dagtickets voor een minder populaire festivaldag blijven vaker nog beschikbaar nadat het volledige weekendticket al uitverkocht is. Ook komen sommige dagtickets pas een paar weken voor het festival in verkoop, zodra de organisatie de precieze bezoekersaantallen beter kan inschatten.\n\n## Extra capaciteit en tweede verkooprondes\n\nSommige festivals openen een tweede verkoopronde, bijvoorbeeld als de line-up wordt uitgebreid of de capaciteit van het terrein wordt aangepast. Dit wordt meestal aangekondigd via de socials en nieuwsbrief van het festival, dus het loont om je in te schrijven, ook als het festival al als uitverkocht wordt getoond.\n\n## Pas op voor malafide verkopers\n\nBij een uitverkocht festival stijgt helaas ook het aantal oplichters. Let op deze signalen:\n\n- **Verkoop via Marktplaats, Instagram-dm''s of Facebookgroepen** buiten een erkend platform om. Hier heb je geen enkele kopersbescherming.\n- **Alleen betalen via een linkje of Tikkie**, zonder dat het ticket via een platform wordt overgedragen.\n- **Een vriend van een vriend die toevallig nog twee tickets over heeft** voor een allang uitverkocht festival: vaak een bekend scriptje bij oplichting rond populaire evenementen.\n- **Prijzen die veel hoger liggen dan het wettelijke maximum** van 120 procent voor Nederlandse doorverkoop: een teken dat de verkoper zich niet aan de regels houdt of geen legitiem ticket heeft.\n\nKoop bij een uitverkocht festival dus altijd via de officiele wachtlijst of een erkend doorverkoopplatform met kopersbescherming. Dat kost soms een paar euro meer aan servicekosten, maar voorkomt dat je met een dure teleurstelling voor een gesloten hek staat.','Uitverkocht festival? Zo kom je er toch nog in','Festival uitverkocht? Ontdek legale manieren om alsnog aan tickets te komen, van wachtlijsten tot doorverkoopplatforms, en herken oplichters op tijd.','2026-07-05T11:00:00Z'),
('eerste-keer-festivalcamping','Eerste keer op festivalcamping: wat je moet weten','Alles wat je moet weten voor je eerste nacht op een festivalcamping, van kosten tot praktische tips.',e'## Basic camping vs. comfort camping\n\nDe meeste grote Nederlandse festivals bieden minimaal twee soorten camping aan:\n\n- **Basic camping** is een grasveld waar je zelf je tent neerzet, met gedeelde toiletten en douches op loopafstand. Dit is de goedkoopste optie en zit vaak al bij het festivalticket inbegrepen of kost een klein bedrag extra, meestal tussen de 20 en 50 euro voor het hele weekend.\n- **Comfort camping** biedt meestal een vaste plek dichter bij de ingang, soms met eigen sanitair, oplaadpunten of een gereserveerd tentvak. Dit kost al snel 75 tot 150 euro extra per persoon, afhankelijk van het festival en het niveau van comfort.\n- Bij sommige festivals kun je ook een **glampingoptie** boeken (opgezette tent of zelfs bed inbegrepen) voor wie liever niet zelf sjouwt: reken dan al snel op enkele honderden euro''s per weekend.\n\nVoor een eerste keer is basic camping prima, zolang je weet waar je aan begint.\n\n## Wat kost een camping-ticket ongeveer?\n\nAls richtlijn: een weekend basic camping bij een groot Nederlands festival kost tussen de 20 en 60 euro bovenop het festivalticket. Comfort camping ligt al snel op 100 tot 200 euro extra per persoon. Check altijd vooraf of stroom, douches en parkeren wel of niet zijn inbegrepen; dat verschilt sterk per festival en per camping-categorie.\n\n## Praktische tips voor je eerste keer\n\n- **Kom op tijd.** Op de eerste camping-dag staan bij populaire festivals vaak lange rijen; hoe eerder je er bent, hoe meer keuze je hebt in een goede tentplek (droog, niet naast de weg naar de toiletten, een beetje uit de wind).\n- **Markeer je tent.** Een vlaggetje, gekleurd lint of ballon op je tentstok maakt je plek in het donker een stuk makkelijker terug te vinden tussen honderden identieke tentjes.\n- **Reken op weinig privacy en geluid.** Zeker op basic camping staan tenten dicht op elkaar en gaat het feest tot diep in de nacht door bij de buren.\n- **Neem een campingstoel en iets om eten op te warmen mee.** Veel campings staan koken met open vuur of gas niet overal toe, check de festivalregels vooraf.\n- **Douchen kost vaak extra of is beperkt beschikbaar.** Bij drukke festivals is een korte koude waterbeurt soms de realiteit; een pakket vochtige doekjes is een prima back-up.\n- **Laat waardevolle spullen niet onbeheerd achter.** Een kluisje bij de camping-ingang is meestal voor een paar euro per dag te huren en de moeite waard voor telefoon, geld en sleutels.\n- **Ga niet alleen.** Een camping vind je in het donker, moe na een lange dag, een stuk makkelijker terug in een groep dan alleen.\n\n## Kort samengevat\n\nBasic camping is voor een eerste festivalervaring ruim voldoende, mits je op tijd komt en met de juiste verwachtingen aan de dag begint. Wil je meer comfort en minder gedoe, dan is een upgrade naar comfort camping vaak het overwegen waard, vooral bij een meerdaags festival.','Eerste keer festivalcamping: complete gids','Op je eerste festivalcamping? Lees het verschil tussen basic en comfort camping, wat het ongeveer kost en praktische tips voor een fijn verblijf.','2026-07-06T13:00:00Z');
